#!/usr/bin/env python3
"""
thesis_lstm_full_pipeline.py

One self-contained pipeline CLI for the thesis NVDA/LSTM workflow.

It embeds the previously separate utilities and exposes them under one command:

  fetch             Fetch StockData EOD/intraday data
  data              Run data-prep stages: news, stock, trends, model dataset, audit
  clean-analyze     Create clean feature set and run feature diagnostics
  train             Run ROCm-safe LSTM random-search or walk-forward backtest
  train-basic       Run one fixed LSTM train/validation/test experiment
  preprocess-minute Expand nested intraday parquet 'data' column
  all               Default end-to-end: data all -> clean/analyze -> optional training

Common examples:

  # Full default data build + clean feature dataset + audit/analysis
  python thesis_lstm_full_pipeline.py all

  # Then run walk-forward training on the cleaned dataset
  python thesis_lstm_full_pipeline.py train walk-forward --auto_threshold --gpu 0

  # Or run random search
  python thesis_lstm_full_pipeline.py train random-search --trials 50 --auto_threshold --gpu 0

  # Delegate to original data pipeline subcommands
  python thesis_lstm_full_pipeline.py data stock-clean-all
  python thesis_lstm_full_pipeline.py data audit

  # Fetch StockData EOD
  python thesis_lstm_full_pipeline.py fetch --mode eod --symbol NVDA --start 2019-03-01 --end 2026-03-01 --csv

Notes:
- StockData fetching requires STOCKDATA_API_TOKEN or STOCKDATA_API_KEY.
- VADER sentiment requires NLTK's vader_lexicon installed/downloaded.
- LSTM commands require TensorFlow/Keras and the ROCm-compatible environment you were using.
"""

from __future__ import annotations

import argparse
import contextlib
import sys
from types import ModuleType
from typing import Iterator, Sequence

_EMBEDDED_SOURCES = {
    'stockdata_fetch': '#!/usr/bin/env python3\n"""\nnvda_stockdata_fetch_combined.py\n\nFetch NVIDIA (NVDA by default) market data from StockData.org and save to Parquet\n(optionally CSV).\n\nThis combines the uploaded EOD and intraday fetchers into one CLI:\n- --mode eod: fetch End-of-Day data, using chunking by default.\n- --mode intraday: fetch intraday data, minute interval by default, using chunks.\n\nAuth env vars (either works):\n- STOCKDATA_API_TOKEN\n- STOCKDATA_API_KEY\n\nExamples:\n  # EOD, recent range, also write CSV\n  python nvda_stockdata_fetch_combined.py --mode eod --start 2026-02-01 --end 2026-03-01 --csv\n\n  # EOD, long range, chunked using API max_period_days when available\n  python nvda_stockdata_fetch_combined.py --mode eod --start 2016-03-01 --end 2026-03-01 --csv\n\n  # Intraday minute data, chunked into 7-day windows\n  python nvda_stockdata_fetch_combined.py --mode intraday --start 2026-02-01 --end 2026-03-01 --csv\n\n  # Different symbol\n  python nvda_stockdata_fetch_combined.py --mode eod --symbol SPY --start 2026-02-01 --csv\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport os\nimport time\nfrom datetime import date, datetime, timedelta\nfrom pathlib import Path\nfrom typing import Any\n\nimport pandas as pd\nimport requests\n\nEOD_API_URL = "https://api.stockdata.org/v1/data/eod"\nINTRADAY_API_URL = "https://api.stockdata.org/v1/data/intraday"\n\n\ndef get_api_token() -> str:\n    """Return the StockData API token from the environment."""\n    for name in ("STOCKDATA_API_TOKEN", "STOCKDATA_API_KEY"):\n        val = os.getenv(name)\n        if val:\n            return val\n    raise RuntimeError(\n        "Missing API token. Export STOCKDATA_API_TOKEN or STOCKDATA_API_KEY "\n        "(for example: source .env)."\n    )\n\n\ndef to_date(s: str) -> date:\n    """Parse YYYY-MM-DD into a date."""\n    return datetime.strptime(s, "%Y-%m-%d").date()\n\n\ndef request_stockdata(url: str, params: dict[str, Any], timeout: int) -> tuple[pd.DataFrame, dict[str, Any]]:\n    """Call StockData, validate the response, and return (dataframe, meta)."""\n    r = requests.get(url, params=params, timeout=timeout)\n    r.raise_for_status()\n    payload = r.json()\n\n    if isinstance(payload, dict) and (payload.get("error") or payload.get("errors")):\n        raise RuntimeError(f"API error: {payload.get(\'error\') or payload.get(\'errors\')}")\n\n    meta = payload.get("meta", {}) if isinstance(payload, dict) else {}\n    data = payload.get("data", []) if isinstance(payload, dict) else []\n    df = pd.DataFrame(data)\n    return df, meta\n\n\ndef normalize_date_column(df: pd.DataFrame) -> pd.DataFrame:\n    """Parse, sort, and normalize the StockData date column when present."""\n    if not df.empty and "date" in df.columns:\n        df = df.copy()\n        df["date"] = pd.to_datetime(df["date"], errors="coerce", utc=True).dt.tz_convert(None)\n        df = df.sort_values("date").reset_index(drop=True)\n    return df\n\n\ndef fetch_eod_window(symbol: str, start: str, end: str, token: str) -> tuple[pd.DataFrame, dict[str, Any]]:\n    params = {\n        "api_token": token,\n        "symbols": symbol,\n        "date_from": start,\n        "date_to": end,\n        "sort": "asc",\n    }\n    df, meta = request_stockdata(EOD_API_URL, params, timeout=60)\n    return normalize_date_column(df), meta\n\n\ndef fetch_intraday_window(\n    symbol: str,\n    start: str,\n    end: str,\n    token: str,\n    interval: str,\n) -> tuple[pd.DataFrame, dict[str, Any]]:\n    params = {\n        "api_token": token,\n        "symbols": symbol,\n        "date_from": start,\n        "date_to": end,\n        "interval": interval,\n        "sort": "asc",\n    }\n    df, meta = request_stockdata(INTRADAY_API_URL, params, timeout=90)\n\n    # Intraday schema may nest OHLCV under a column named \'data\'.\n    if not df.empty and "data" in df.columns and isinstance(df.loc[df.index[0], "data"], dict):\n        nested = pd.json_normalize(df["data"])\n        df = pd.concat([df.drop(columns=["data"]), nested], axis=1)\n\n    return normalize_date_column(df), meta\n\n\ndef write_outputs(\n    df: pd.DataFrame,\n    outdir: Path,\n    symbol: str,\n    mode: str,\n    start: str,\n    end: str,\n    csv: bool,\n    interval: str | None = None,\n) -> None:\n    """Write Parquet, and CSV when requested."""\n    descriptor = "eod" if mode == "eod" else f"intraday_{interval}"\n    pq = outdir / f"{symbol}_{descriptor}_{start}_to_{end}.parquet"\n    df.to_parquet(pq, index=False)\n    print(f"Wrote {len(df):,} rows -> {pq}")\n\n    if csv:\n        csvp = outdir / f"{symbol}_{descriptor}_{start}_to_{end}.csv"\n        df.to_csv(csvp, index=False)\n        print(f"Wrote {len(df):,} rows -> {csvp}")\n\n\ndef combine_windows(dfs: list[pd.DataFrame]) -> pd.DataFrame:\n    """Concatenate, sort, and deduplicate window results."""\n    out = pd.concat(dfs, ignore_index=True)\n    if "date" in out.columns:\n        out = out.sort_values("date").drop_duplicates(subset=["date"], keep="last").reset_index(drop=True)\n    return out\n\n\ndef run_eod(args: argparse.Namespace, token: str, outdir: Path) -> None:\n    start_d = to_date(args.start)\n    end_d = to_date(args.end)\n    if end_d < start_d:\n        raise ValueError("--end must be >= --start")\n\n    if args.max_days and args.max_days > 0:\n        effective_max_days = args.max_days\n        print(f"Using overridden max_days={effective_max_days}")\n    else:\n        probe_end = min(end_d, start_d + timedelta(days=1))\n        _, meta = fetch_eod_window(args.symbol, start_d.strftime("%Y-%m-%d"), probe_end.strftime("%Y-%m-%d"), token)\n        effective_max_days = int(meta.get("max_period_days") or 180)\n        print(f"Using API max_period_days={effective_max_days} (fallback 180 if missing). meta={meta}")\n\n    all_dfs: list[pd.DataFrame] = []\n    cur = start_d\n    empty_windows = 0\n\n    while cur <= end_d:\n        win_end = min(end_d, cur + timedelta(days=effective_max_days - 1))\n        s = cur.strftime("%Y-%m-%d")\n        e = win_end.strftime("%Y-%m-%d")\n\n        print(f"Fetching {args.symbol} EOD: {s} .. {e}")\n        df, meta = fetch_eod_window(args.symbol, s, e, token)\n        print(f"  rows={len(df):,} meta={meta}")\n\n        if df.empty:\n            empty_windows += 1\n            if not args.continue_on_empty:\n                print(\n                    "Stopping because this EOD window returned 0 rows. "\n                    "This usually means your plan does not include data for this period, "\n                    "or the symbol/date range is invalid."\n                )\n                break\n        else:\n            all_dfs.append(df)\n\n        cur = win_end + timedelta(days=1)\n        if cur <= end_d and args.sleep > 0:\n            time.sleep(args.sleep)\n\n    if not all_dfs:\n        print(f"No EOD data downloaded for {args.symbol}. Empty windows encountered: {empty_windows}.")\n        return\n\n    out = combine_windows(all_dfs)\n    write_outputs(out, outdir, args.symbol, "eod", args.start, args.end, args.csv)\n\n\ndef run_intraday(args: argparse.Namespace, token: str, outdir: Path) -> None:\n    start_d = to_date(args.start)\n    end_d = to_date(args.end)\n    if end_d < start_d:\n        raise ValueError("--end must be >= --start")\n    if args.chunk_days <= 0:\n        raise ValueError("--chunk_days must be > 0")\n\n    all_dfs: list[pd.DataFrame] = []\n    cur = start_d\n\n    while cur <= end_d:\n        chunk_end = min(end_d, cur + timedelta(days=args.chunk_days - 1))\n        s = cur.strftime("%Y-%m-%d")\n        e = chunk_end.strftime("%Y-%m-%d")\n\n        print(f"Fetching {args.symbol} {args.interval}: {s} .. {e}")\n        df, meta = fetch_intraday_window(args.symbol, s, e, token, args.interval)\n        print(f"  rows={len(df):,} meta={meta}")\n        if not df.empty:\n            all_dfs.append(df)\n        elif not args.continue_on_empty:\n            print(\n                "Stopping because this intraday window returned 0 rows. "\n                "Try a more recent range if your plan only includes recent intraday history."\n            )\n            break\n\n        cur = chunk_end + timedelta(days=1)\n        if cur <= end_d and args.sleep > 0:\n            time.sleep(args.sleep)\n\n    if not all_dfs:\n        print(f"No intraday data downloaded for {args.symbol}.")\n        return\n\n    out = combine_windows(all_dfs)\n    write_outputs(out, outdir, args.symbol, "intraday", args.start, args.end, args.csv, interval=args.interval)\n\n\ndef build_parser() -> argparse.ArgumentParser:\n    p = argparse.ArgumentParser(\n        description="Fetch StockData.org EOD or intraday data in chunks (default symbol: NVDA)."\n    )\n    p.add_argument("--mode", choices=("eod", "intraday"), default="eod", help="Data type to fetch (default: eod)")\n    p.add_argument("--symbol", default="NVDA", help="Ticker symbol (default: NVDA)")\n    p.add_argument("--start", default="2026-01-31", help="Start date YYYY-MM-DD")\n    p.add_argument("--end", default=str(date.today()), help="End date YYYY-MM-DD (default: today)")\n    p.add_argument("--outdir", default="./data", help="Output directory (default: ./data)")\n    p.add_argument("--csv", action="store_true", help="Also write CSV (Parquet is always written)")\n    p.add_argument("--sleep", type=float, default=0.5, help="Seconds to sleep between requests (default: 0.5)")\n    p.add_argument(\n        "--continue_on_empty",\n        action="store_true",\n        help="Continue fetching subsequent windows even if one window returns 0 rows.",\n    )\n\n    eod = p.add_argument_group("EOD options")\n    eod.add_argument(\n        "--max_days",\n        type=int,\n        default=0,\n        help="EOD max days per request. If 0, use API meta.max_period_days when available (else 180).",\n    )\n\n    intraday = p.add_argument_group("Intraday options")\n    intraday.add_argument("--interval", default="minute", help="Intraday interval (default: minute)")\n    intraday.add_argument("--chunk_days", type=int, default=7, help="Intraday days per request (default: 7)")\n    return p\n\n\ndef main() -> None:\n    parser = build_parser()\n    args = parser.parse_args()\n\n    token = get_api_token()\n    outdir = Path(args.outdir)\n    outdir.mkdir(parents=True, exist_ok=True)\n\n    if args.mode == "eod":\n        run_eod(args, token, outdir)\n    else:\n        run_intraday(args, token, outdir)\n\n\nif __name__ == "__main__":\n    main()\n',
    'data_pipeline': '#!/usr/bin/env python3\n"""\ndata_pipeline_combined.py\n\nOne CLI for the thesis dataset pipeline:\n- combine raw news CSVs\n- clean / trading-align news headlines\n- build daily VADER sentiment factors\n- process EOD stock data\n- process Google Trends data\n- build the final model dataset\n- validate the final dataset in console\n- write an Excel audit report\n\nExamples:\n  python data_pipeline_combined.py news-combine\n  python data_pipeline_combined.py news-clean\n  python data_pipeline_combined.py news-sentiment\n  python data_pipeline_combined.py stock-clean --symbol NVDA --input /path/NVDA.csv --output /path/NVDA_eod_processed.csv\n  python data_pipeline_combined.py trends-clean\n  python data_pipeline_combined.py build-model\n  python data_pipeline_combined.py validate\n  python data_pipeline_combined.py audit\n  python data_pipeline_combined.py all\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport glob\nimport os\nfrom pathlib import Path\nfrom typing import Iterable\n\nimport numpy as np\nimport pandas as pd\n\n\n# -----------------------------------------------------------------------------\n# Default project paths\n# -----------------------------------------------------------------------------\nBASE_DIR = Path("/home/zammorak/thesis/data")\n\nRAW_NEWS_DIR = BASE_DIR / "raw/news_headlines"\nNEWS_MASTER_PATH = BASE_DIR / "interim/news_headlines_master.csv"\nNEWS_CLEAN_PATH = BASE_DIR / "processed/news_headlines_clean.csv"\nNEWS_SENTIMENT_PATH = BASE_DIR / "processed/news_daily_sentiment.csv"\n\nTRENDS_RAW_PATH = BASE_DIR / "interim/nvidia_trends_daily_consistent.csv"\nTRENDS_PROCESSED_PATH = BASE_DIR / "processed/nvidia_trends_processed.csv"\n\nMODEL_DIR = BASE_DIR / "model_feed"\nMODEL_DATASET_PATH = MODEL_DIR / "model_dataset.csv"\nMODEL_AUDIT_PATH = MODEL_DIR / "model_dataset_audit.xlsx"\n\nDEFAULT_STOCK_INPUTS = {\n    "NVDA": BASE_DIR / "raw/stock_data/NVDA/NVDA_eod_chunked_2019-03-01_to_2026-03-01.csv",\n    "SPY": BASE_DIR / "raw/macro_stock_data/SPY/SPY_eod_chunked_2019-03-01_to_2026-03-01.csv",\n    "SOXX": BASE_DIR / "raw/macro_stock_data/SOXX/SOXX_eod_chunked_2019-03-01_to_2026-03-01.csv",\n    "IEF": BASE_DIR / "raw/macro_stock_data/IEF/IEF_eod_chunked_2019-03-01_to_2026-03-01.csv",\n}\nDEFAULT_STOCK_OUTPUTS = {\n    symbol: BASE_DIR / f"processed/{symbol}_eod_processed.csv"\n    for symbol in DEFAULT_STOCK_INPUTS\n}\n\n\n# -----------------------------------------------------------------------------\n# Helpers\n# -----------------------------------------------------------------------------\ndef ensure_parent(path: str | Path) -> None:\n    Path(path).parent.mkdir(parents=True, exist_ok=True)\n\n\ndef standardize_columns(cols: Iterable[object]) -> pd.Index:\n    return (\n        pd.Index(cols)\n        .astype(str)\n        .str.strip()\n        .str.lower()\n        .str.replace(" ", "_", regex=False)\n    )\n\n\ndef print_done(message: str, path: str | Path | None = None) -> None:\n    print(f"✅ {message}")\n    if path is not None:\n        print(f"Saved to: {path}")\n\n\n# -----------------------------------------------------------------------------\n# News: combine raw CSVs\n# -----------------------------------------------------------------------------\ndef combine_all_news_csvs(\n    folder_path: str | Path = RAW_NEWS_DIR,\n    output_path: str | Path = NEWS_MASTER_PATH,\n    recursive: bool = False,\n) -> pd.DataFrame:\n    folder_path = Path(folder_path)\n    output_path = Path(output_path)\n    pattern = "**/*.csv" if recursive else "*.csv"\n    files = sorted(glob.glob(str(folder_path / pattern), recursive=recursive))\n    if not files:\n        raise FileNotFoundError(f"No CSV files found in: {folder_path}")\n\n    all_cols: list[pd.Index] = []\n    for fp in files:\n        header_df = pd.read_csv(fp, nrows=0)\n        all_cols.append(standardize_columns(header_df.columns))\n\n    union_cols = pd.Index([])\n    for cols in all_cols:\n        union_cols = union_cols.union(cols)\n\n    preferred_order = [\n        "symbol_target", "uuid", "published_at", "date", "title", "description",\n        "keywords", "snippet", "url", "source", "image_url", "entities_json", "raw_json",\n    ]\n    preferred_present = [c for c in preferred_order if c in union_cols]\n    remaining = sorted([c for c in union_cols if c not in preferred_present])\n    canonical_cols = preferred_present + remaining\n\n    frames = []\n    for fp in files:\n        df = pd.read_csv(fp)\n        df.columns = standardize_columns(df.columns)\n        if "source_file" not in canonical_cols:\n            canonical_cols.append("source_file")\n        df = df.reindex(columns=canonical_cols)\n        df["source_file"] = os.path.basename(fp)\n        frames.append(df)\n\n    combined = pd.concat(frames, ignore_index=True)\n    if "published_at" in combined.columns:\n        combined["published_at"] = pd.to_datetime(combined["published_at"], errors="coerce", utc=True)\n\n    if "uuid" in combined.columns:\n        combined = combined.drop_duplicates(subset=["uuid"], keep="first")\n    else:\n        combined = combined.drop_duplicates()\n\n    combined = combined.reset_index(drop=True)\n    ensure_parent(output_path)\n    combined.to_csv(output_path, index=False)\n    return combined\n\n\n# -----------------------------------------------------------------------------\n# News: clean and trading-align\n# -----------------------------------------------------------------------------\ndef clean_news_dataset(\n    input_path: str | Path = NEWS_MASTER_PATH,\n    output_path: str | Path = NEWS_CLEAN_PATH,\n) -> pd.DataFrame:\n    df = pd.read_csv(input_path)\n    df.columns = standardize_columns(df.columns)\n\n    required_cols = ["symbol_target", "published_at", "title", "description", "keywords", "source"]\n    missing_cols = [c for c in required_cols if c not in df.columns]\n    if missing_cols:\n        raise ValueError(f"Missing required columns: {missing_cols}")\n\n    df = df[required_cols].copy()\n    text_cols = ["title", "description", "keywords", "source"]\n    for col in text_cols:\n        df[col] = df[col].where(df[col].notna(), None)\n        df[col] = df[col].astype(str).str.strip()\n        df[col] = df[col].replace({"": None, "nan": None, "None": None})\n\n    df = df[df["title"].notna()]\n    df["published_at"] = pd.to_datetime(df["published_at"], errors="coerce", utc=True)\n    df = df[df["published_at"].notna()]\n\n    # US equities trading alignment: 16:00 ET close.\n    df["published_et"] = df["published_at"].dt.tz_convert("America/New_York")\n    df["weekday_et"] = df["published_et"].dt.weekday\n    df = df[df["weekday_et"] < 5].copy()\n\n    df["trading_date"] = df["published_et"].dt.floor("D")\n    after_close_mask = df["published_et"].dt.hour >= 16\n    df.loc[after_close_mask, "trading_date"] = df.loc[after_close_mask, "trading_date"] + pd.Timedelta(days=1)\n\n    saturday_mask = df["trading_date"].dt.weekday == 5\n    sunday_mask = df["trading_date"].dt.weekday == 6\n    df.loc[saturday_mask, "trading_date"] = df.loc[saturday_mask, "trading_date"] + pd.Timedelta(days=2)\n    df.loc[sunday_mask, "trading_date"] = df.loc[sunday_mask, "trading_date"] + pd.Timedelta(days=1)\n    df["trading_date"] = df["trading_date"].dt.date\n\n    df["date"] = df["published_at"].dt.date\n    df["year"] = df["published_at"].dt.year\n    df["month"] = df["published_at"].dt.month\n    df["day"] = df["published_at"].dt.day\n    df["hour"] = df["published_at"].dt.hour\n    df["weekday"] = df["published_at"].dt.weekday\n    df["is_weekend"] = df["weekday"] >= 5\n\n    df = df.sort_values("published_at").reset_index(drop=True)\n    df = df.drop(columns=["weekday_et"], errors="ignore")\n\n    ensure_parent(output_path)\n    df.to_csv(output_path, index=False)\n    return df\n\n\n# -----------------------------------------------------------------------------\n# News: sentiment\n# -----------------------------------------------------------------------------\ndef build_daily_sentiment(\n    input_path: str | Path = NEWS_CLEAN_PATH,\n    output_path: str | Path = NEWS_SENTIMENT_PATH,\n) -> pd.DataFrame:\n    from nltk.sentiment.vader import SentimentIntensityAnalyzer\n\n    df = pd.read_csv(input_path)\n    df["published_at"] = pd.to_datetime(df["published_at"], utc=True)\n    if "trading_date" not in df.columns:\n        raise ValueError("trading_date column missing. Run news-clean first.")\n\n    sid = SentimentIntensityAnalyzer()\n    df["text_for_sentiment"] = df["title"].fillna("") + ". " + df["description"].fillna("")\n    df["sentiment"] = df["text_for_sentiment"].apply(lambda x: sid.polarity_scores(x)["compound"])\n\n    daily = df.groupby("trading_date").agg(\n        avg_sentiment=("sentiment", "mean"),\n        median_sentiment=("sentiment", "median"),\n        sentiment_std=("sentiment", "std"),\n        news_count=("sentiment", "count"),\n        positive_ratio=("sentiment", lambda x: np.mean(x > 0)),\n        negative_ratio=("sentiment", lambda x: np.mean(x < 0)),\n    ).reset_index()\n    daily["sentiment_std"] = daily["sentiment_std"].fillna(0)\n    daily = daily.sort_values("trading_date").reset_index(drop=True)\n\n    ensure_parent(output_path)\n    daily.to_csv(output_path, index=False)\n    return daily\n\n\n# -----------------------------------------------------------------------------\n# Stock EOD processing\n# -----------------------------------------------------------------------------\ndef clean_and_process_eod(\n    input_path: str | Path,\n    output_path: str | Path,\n) -> pd.DataFrame:\n    df = pd.read_csv(input_path)\n    df.columns = standardize_columns(df.columns)\n\n    required_price_cols = ["date", "open", "high", "low", "close"]\n    missing = [c for c in required_price_cols if c not in df.columns]\n    if missing:\n        raise ValueError(f"Missing required columns: {missing}")\n\n    df["date"] = pd.to_datetime(df["date"], errors="coerce")\n    df = df[df["date"].notna()]\n    df = df.drop_duplicates(subset=["date"])\n    df = df.sort_values("date").reset_index(drop=True)\n\n    df["return"] = df["close"].pct_change()\n    df["log_return"] = np.log(df["close"] / df["close"].shift(1))\n    df["intraday_return"] = (df["close"] - df["open"]) / df["open"]\n    df["overnight_return"] = (df["open"] - df["close"].shift(1)) / df["close"].shift(1)\n    df["volatility_20d"] = df["log_return"].rolling(20).std()\n    df["momentum_5d"] = df["log_return"].rolling(5).mean()\n    df["momentum_20d"] = df["log_return"].rolling(20).mean()\n\n    if "volume" in df.columns:\n        df["volume_change"] = df["volume"].pct_change()\n        df["volume_20d_avg"] = df["volume"].rolling(20).mean()\n\n    df["target_next_return"] = df["log_return"].shift(-1)\n    df["target_direction"] = (df["target_next_return"] > 0).astype(int)\n\n    df = df.dropna().reset_index(drop=True)\n    ensure_parent(output_path)\n    df.to_csv(output_path, index=False)\n    return df\n\n\n# -----------------------------------------------------------------------------\n# Trends processing\n# -----------------------------------------------------------------------------\ndef clean_and_process_trends(\n    input_path: str | Path = TRENDS_RAW_PATH,\n    output_path: str | Path = TRENDS_PROCESSED_PATH,\n) -> pd.DataFrame:\n    df = pd.read_csv(input_path)\n    df.columns = standardize_columns(df.columns)\n\n    if "date" not in df.columns:\n        raise ValueError("No \'date\' column found in trends data.")\n\n    value_cols = [c for c in df.columns if c != "date"]\n    if len(value_cols) != 1:\n        raise ValueError("Unexpected trends structure. Should contain one value column plus date.")\n\n    trend_col = value_cols[0]\n    df["date"] = pd.to_datetime(df["date"], errors="coerce")\n    df = df[df["date"].notna()].sort_values("date").reset_index(drop=True)\n    df = df.rename(columns={trend_col: "trends_raw"})\n    df["trends_raw"] = pd.to_numeric(df["trends_raw"], errors="coerce")\n\n    df["trends_7d_ma"] = df["trends_raw"].rolling(7).mean()\n    df["trends_momentum_7d"] = df["trends_raw"].pct_change(7)\n    rolling_mean = df["trends_raw"].rolling(30).mean()\n    rolling_std = df["trends_raw"].rolling(30).std()\n    df["trends_zscore_30d"] = (df["trends_raw"] - rolling_mean) / rolling_std\n    df["trends_spike"] = (df["trends_zscore_30d"] > 2).astype(int)\n\n    df = df.dropna().reset_index(drop=True)\n    ensure_parent(output_path)\n    df.to_csv(output_path, index=False)\n    return df\n\n\n# -----------------------------------------------------------------------------\n# Build model dataset\n# -----------------------------------------------------------------------------\ndef build_model_dataset(\n    nvda_path: str | Path = DEFAULT_STOCK_OUTPUTS["NVDA"],\n    spy_path: str | Path = DEFAULT_STOCK_OUTPUTS["SPY"],\n    soxx_path: str | Path = DEFAULT_STOCK_OUTPUTS["SOXX"],\n    ief_path: str | Path = DEFAULT_STOCK_OUTPUTS["IEF"],\n    sent_path: str | Path = NEWS_SENTIMENT_PATH,\n    trends_path: str | Path = TRENDS_PROCESSED_PATH,\n    output_path: str | Path = MODEL_DATASET_PATH,\n) -> pd.DataFrame:\n    nvda = pd.read_csv(nvda_path)\n    spy = pd.read_csv(spy_path)\n    soxx = pd.read_csv(soxx_path)\n    ief = pd.read_csv(ief_path)\n    sent = pd.read_csv(sent_path)\n    trends = pd.read_csv(trends_path)\n\n    for frame in [nvda, spy, soxx, ief, trends]:\n        frame["date"] = pd.to_datetime(frame["date"])\n    sent["trading_date"] = pd.to_datetime(sent["trading_date"])\n\n    spy = spy[["date", "log_return"]].rename(columns={"log_return": "spy_return"})\n    soxx = soxx[["date", "log_return"]].rename(columns={"log_return": "soxx_return"})\n    ief = ief[["date", "log_return"]].rename(columns={"log_return": "ief_return"})\n\n    df = nvda.merge(spy, on="date", how="left")\n    df = df.merge(soxx, on="date", how="left")\n    df = df.merge(ief, on="date", how="left")\n    df = df.merge(sent, left_on="date", right_on="trading_date", how="left")\n    df = df.drop(columns=["trading_date"], errors="ignore")\n    df = df.merge(trends, on="date", how="left")\n    df = df.sort_values("date")\n\n    fill_cols = [\n        "avg_sentiment", "median_sentiment", "sentiment_std", "news_count",\n        "positive_ratio", "negative_ratio", "trends_raw", "trends_7d_ma",\n        "trends_momentum_7d", "trends_zscore_30d", "trends_spike",\n    ]\n    existing_fill_cols = [c for c in fill_cols if c in df.columns]\n    df[existing_fill_cols] = df[existing_fill_cols].ffill()\n\n    df = df.dropna().reset_index(drop=True)\n    ensure_parent(output_path)\n    df.to_csv(output_path, index=False)\n    return df\n\n\n# -----------------------------------------------------------------------------\n# Validation and audit\n# -----------------------------------------------------------------------------\ndef dataset_validation_tables(data_path: str | Path = MODEL_DATASET_PATH) -> dict[str, pd.DataFrame]:\n    df = pd.read_csv(data_path)\n    df["date"] = pd.to_datetime(df["date"])\n    df = df.sort_values("date").reset_index(drop=True)\n\n    basic_info = pd.DataFrame({\n        "metric": ["rows", "columns", "date_min", "date_max"],\n        "value": [len(df), len(df.columns), df["date"].min(), df["date"].max()],\n    })\n\n    dup_mask = df["date"].duplicated(keep=False)\n    duplicate_dates = df.loc[dup_mask, ["date"]].copy()\n    if not duplicate_dates.empty:\n        duplicate_dates["count_for_date"] = duplicate_dates.groupby("date")["date"].transform("count")\n        duplicate_dates = duplicate_dates.sort_values(["date"]).drop_duplicates()\n    dup_summary = pd.DataFrame({\n        "duplicate_dates_total": [int(df["date"].duplicated().sum())],\n        "unique_dates_duplicated": [int(duplicate_dates["date"].nunique()) if not duplicate_dates.empty else 0],\n    })\n\n    date_diffs = df["date"].diff().dt.days\n    gaps = pd.DataFrame({"date": df["date"], "gap_days_since_prev": date_diffs})\n    large_gaps = gaps[gaps["gap_days_since_prev"] > 3].copy()\n    max_gap = pd.DataFrame({"max_gap_days": [float(date_diffs.max())]})\n\n    missing_table = pd.DataFrame({\n        "missing_count": df.isna().sum().sort_values(ascending=False),\n        "missing_pct": (df.isna().mean() * 100).round(2).sort_values(ascending=False),\n    })\n    missing_table = missing_table[missing_table["missing_count"] > 0]\n    if missing_table.empty:\n        missing_table = pd.DataFrame({"note": ["No missing values detected ✅"]})\n\n    zero_var_table = df.nunique(dropna=False)\n    zero_var_table = zero_var_table[zero_var_table <= 1].sort_values().to_frame("n_unique_values")\n    if zero_var_table.empty:\n        zero_var_table = pd.DataFrame({"note": ["No zero-variance columns ✅"]})\n\n    sanity_rows = []\n    for col, label in [\n        ("log_return", "Return"),\n        ("avg_sentiment", "Sentiment"),\n        ("trends_zscore_30d", "Trends z-score (30d)"),\n    ]:\n        if col in df.columns:\n            s = df[col].dropna()\n            sanity_rows += [\n                {"metric": f"{label} mean", "value": np.mean(s)},\n                {"metric": f"{label} std", "value": np.std(s)},\n                {"metric": f"{label} min", "value": np.min(s)},\n                {"metric": f"{label} max", "value": np.max(s)},\n            ]\n        else:\n            sanity_rows.append({"metric": f"{label} (missing column)", "value": "N/A"})\n    sanity_checks = pd.DataFrame(sanity_rows)\n\n    if "target_next_return" in df.columns:\n        corr = df.corr(numeric_only=True)\n        corr_target = corr["target_next_return"].sort_values(ascending=False).to_frame("corr_with_target_next_return")\n    else:\n        corr_target = pd.DataFrame({"note": ["Column target_next_return not found"]})\n\n    if "trends_zscore_30d" in df.columns and "target_next_return" in df.columns:\n        df_tmp = df.copy()\n        df_tmp["trends_z_lag1"] = df_tmp["trends_zscore_30d"].shift(1)\n        df_tmp["trends_z_lag2"] = df_tmp["trends_zscore_30d"].shift(2)\n        lag_corrs = pd.DataFrame({\n            "feature": ["trends_z_lag1", "trends_z_lag2"],\n            "corr_with_target_next_return": [\n                df_tmp["trends_z_lag1"].corr(df_tmp["target_next_return"]),\n                df_tmp["trends_z_lag2"].corr(df_tmp["target_next_return"]),\n            ],\n        })\n    else:\n        lag_corrs = pd.DataFrame({"note": ["Required columns missing: trends_zscore_30d and/or target_next_return"]})\n\n    if "trends_spike" in df.columns and "target_next_return" in df.columns:\n        group_trends = df.groupby("trends_spike")["target_next_return"].mean().to_frame("mean_target_next_return")\n    else:\n        group_trends = pd.DataFrame({"note": ["Required columns missing: trends_spike and/or target_next_return"]})\n\n    return {\n        "basic_info": basic_info,\n        "dup_summary": dup_summary,\n        "duplicate_dates": duplicate_dates,\n        "max_gap": max_gap,\n        "large_gaps": large_gaps,\n        "missing_table": missing_table,\n        "zero_var_table": zero_var_table,\n        "sanity_checks": sanity_checks,\n        "corr_target": corr_target,\n        "lag_corrs": lag_corrs,\n        "group_trends": group_trends,\n    }\n\n\ndef validate_dataset(data_path: str | Path = MODEL_DATASET_PATH) -> None:\n    tables = dataset_validation_tables(data_path)\n    print("===================================")\n    print("BASIC INFO")\n    print("===================================")\n    print(tables["basic_info"].to_string(index=False))\n    print("\\nDuplicate summary:")\n    print(tables["dup_summary"].to_string(index=False))\n    print("\\nMax gap:")\n    print(tables["max_gap"].to_string(index=False))\n    print("\\nPotential abnormal gaps (>3 days):")\n    print(tables["large_gaps"].to_string(index=False))\n    print("\\nMissing values:")\n    print(tables["missing_table"].to_string())\n    print("\\nZero variance columns:")\n    print(tables["zero_var_table"].to_string())\n    print("\\nSanity checks:")\n    print(tables["sanity_checks"].to_string(index=False))\n    print("\\nCorrelation with target_next_return:")\n    print(tables["corr_target"].to_string())\n    print("\\nLag correlations:")\n    print(tables["lag_corrs"].to_string(index=False))\n    print("\\nGroup by trends_spike:")\n    print(tables["group_trends"].to_string())\n\n\ndef write_audit_workbook(\n    data_path: str | Path = MODEL_DATASET_PATH,\n    out_path: str | Path = MODEL_AUDIT_PATH,\n) -> None:\n    tables = dataset_validation_tables(data_path)\n    out_path = Path(out_path)\n    ensure_parent(out_path)\n\n    with pd.ExcelWriter(out_path, engine="xlsxwriter", datetime_format="yyyy-mm-dd") as writer:\n        workbook = writer.book\n        header_fmt = workbook.add_format({"bold": True, "bg_color": "#F2F2F2", "border": 1})\n        cell_fmt = workbook.add_format({"border": 1})\n\n        def write_sheet(df_sheet: pd.DataFrame, name: str, index: bool = True, freeze=(1, 0), autofilter=True):\n            df_sheet.to_excel(writer, sheet_name=name, index=index)\n            ws = writer.sheets[name]\n            ws.freeze_panes(*freeze)\n            ws.set_row(0, None, header_fmt)\n            width_df = df_sheet.reset_index() if index else df_sheet\n            for col_idx, col_name in enumerate(width_df.columns):\n                series_as_str = width_df.iloc[:, col_idx].astype(str) if len(width_df) else pd.Series(dtype=str)\n                max_len = max([len(str(col_name))] + series_as_str.map(len).tolist())\n                ws.set_column(col_idx, col_idx, min(max_len + 2, 50), cell_fmt)\n            if autofilter:\n                rows, cols = width_df.shape\n                ws.autofilter(0, 0, rows, max(cols - 1, 0))\n\n        write_sheet(tables["basic_info"], "Basic_Info", index=False)\n        write_sheet(tables["dup_summary"], "Duplicate_Dates", index=False)\n        write_sheet(tables["duplicate_dates"].set_index("date") if not tables["duplicate_dates"].empty else pd.DataFrame({"note": ["No duplicate dates ✅"]}), "Duplicate_Dates_List")\n        write_sheet(tables["max_gap"], "Date_Gaps", index=False)\n        write_sheet(tables["large_gaps"].set_index("date") if not tables["large_gaps"].empty else pd.DataFrame({"note": ["No large gaps >3 days ✅"]}), "Large_Gaps_List")\n        write_sheet(tables["missing_table"], "Missing_Values")\n        write_sheet(tables["zero_var_table"], "Zero_Variance")\n        write_sheet(tables["sanity_checks"], "Sanity_Checks", index=False)\n        write_sheet(tables["corr_target"], "Corr_TargetNextReturn")\n        write_sheet(tables["lag_corrs"].set_index("feature") if "feature" in tables["lag_corrs"].columns else tables["lag_corrs"], "Lag_Corrs")\n        write_sheet(tables["group_trends"], "Group_TrendsSpike")\n\n    print_done("Wrote audit workbook", out_path)\n\n\n# -----------------------------------------------------------------------------\n# CLI\n# -----------------------------------------------------------------------------\ndef build_parser() -> argparse.ArgumentParser:\n    parser = argparse.ArgumentParser(description="Combined thesis data pipeline utility.")\n    sub = parser.add_subparsers(dest="command", required=True)\n\n    p = sub.add_parser("news-combine", help="Combine raw news CSV files into one master file.")\n    p.add_argument("--folder", default=str(RAW_NEWS_DIR))\n    p.add_argument("--output", default=str(NEWS_MASTER_PATH))\n    p.add_argument("--recursive", action="store_true")\n\n    p = sub.add_parser("news-clean", help="Clean and trading-align combined news headlines.")\n    p.add_argument("--input", default=str(NEWS_MASTER_PATH))\n    p.add_argument("--output", default=str(NEWS_CLEAN_PATH))\n\n    p = sub.add_parser("news-sentiment", help="Build daily VADER sentiment factors.")\n    p.add_argument("--input", default=str(NEWS_CLEAN_PATH))\n    p.add_argument("--output", default=str(NEWS_SENTIMENT_PATH))\n\n    p = sub.add_parser("stock-clean", help="Clean/process one EOD stock CSV.")\n    p.add_argument("--symbol", choices=sorted(DEFAULT_STOCK_INPUTS), default="NVDA")\n    p.add_argument("--input", default=None, help="Defaults to the configured path for --symbol.")\n    p.add_argument("--output", default=None, help="Defaults to the configured processed path for --symbol.")\n\n    p = sub.add_parser("stock-clean-all", help="Clean/process NVDA, SPY, SOXX, and IEF using default paths.")\n\n    p = sub.add_parser("trends-clean", help="Clean and feature-engineer Google Trends data.")\n    p.add_argument("--input", default=str(TRENDS_RAW_PATH))\n    p.add_argument("--output", default=str(TRENDS_PROCESSED_PATH))\n\n    p = sub.add_parser("build-model", help="Merge processed stock, sentiment, and trends data into model_dataset.csv.")\n    p.add_argument("--output", default=str(MODEL_DATASET_PATH))\n    p.add_argument("--nvda", default=str(DEFAULT_STOCK_OUTPUTS["NVDA"]))\n    p.add_argument("--spy", default=str(DEFAULT_STOCK_OUTPUTS["SPY"]))\n    p.add_argument("--soxx", default=str(DEFAULT_STOCK_OUTPUTS["SOXX"]))\n    p.add_argument("--ief", default=str(DEFAULT_STOCK_OUTPUTS["IEF"]))\n    p.add_argument("--sentiment", default=str(NEWS_SENTIMENT_PATH))\n    p.add_argument("--trends", default=str(TRENDS_PROCESSED_PATH))\n\n    p = sub.add_parser("validate", help="Print final dataset validation checks.")\n    p.add_argument("--input", default=str(MODEL_DATASET_PATH))\n\n    p = sub.add_parser("audit", help="Write Excel audit workbook for final dataset.")\n    p.add_argument("--input", default=str(MODEL_DATASET_PATH))\n    p.add_argument("--output", default=str(MODEL_AUDIT_PATH))\n\n    p = sub.add_parser("all", help="Run the full default pipeline and write validation/audit outputs.")\n    p.add_argument("--recursive-news", action="store_true")\n\n    return parser\n\n\ndef main() -> None:\n    args = build_parser().parse_args()\n\n    if args.command == "news-combine":\n        df = combine_all_news_csvs(args.folder, args.output, args.recursive)\n        print_done(f"Combined news CSVs. Rows: {len(df):,}; Columns: {len(df.columns):,}", args.output)\n\n    elif args.command == "news-clean":\n        df = clean_news_dataset(args.input, args.output)\n        print_done(f"Cleaned and trading-aligned news. Rows: {len(df):,}; Columns: {len(df.columns):,}", args.output)\n\n    elif args.command == "news-sentiment":\n        df = build_daily_sentiment(args.input, args.output)\n        print_done(f"Built daily sentiment. Rows: {len(df):,}; Columns: {len(df.columns):,}", args.output)\n\n    elif args.command == "stock-clean":\n        input_path = Path(args.input) if args.input else DEFAULT_STOCK_INPUTS[args.symbol]\n        output_path = Path(args.output) if args.output else DEFAULT_STOCK_OUTPUTS[args.symbol]\n        df = clean_and_process_eod(input_path, output_path)\n        print_done(f"Processed {args.symbol} EOD. Rows: {len(df):,}; Columns: {len(df.columns):,}", output_path)\n\n    elif args.command == "stock-clean-all":\n        for symbol in ["NVDA", "SPY", "SOXX", "IEF"]:\n            df = clean_and_process_eod(DEFAULT_STOCK_INPUTS[symbol], DEFAULT_STOCK_OUTPUTS[symbol])\n            print_done(f"Processed {symbol} EOD. Rows: {len(df):,}; Columns: {len(df.columns):,}", DEFAULT_STOCK_OUTPUTS[symbol])\n\n    elif args.command == "trends-clean":\n        df = clean_and_process_trends(args.input, args.output)\n        print_done(f"Processed trends. Rows: {len(df):,}; Columns: {len(df.columns):,}", args.output)\n\n    elif args.command == "build-model":\n        df = build_model_dataset(args.nvda, args.spy, args.soxx, args.ief, args.sentiment, args.trends, args.output)\n        print_done(f"Built model dataset. Rows: {len(df):,}; Columns: {len(df.columns):,}", args.output)\n\n    elif args.command == "validate":\n        validate_dataset(args.input)\n\n    elif args.command == "audit":\n        write_audit_workbook(args.input, args.output)\n\n    elif args.command == "all":\n        df = combine_all_news_csvs(RAW_NEWS_DIR, NEWS_MASTER_PATH, recursive=args.recursive_news)\n        print_done(f"Combined news CSVs. Rows: {len(df):,}", NEWS_MASTER_PATH)\n        df = clean_news_dataset(NEWS_MASTER_PATH, NEWS_CLEAN_PATH)\n        print_done(f"Cleaned news. Rows: {len(df):,}", NEWS_CLEAN_PATH)\n        df = build_daily_sentiment(NEWS_CLEAN_PATH, NEWS_SENTIMENT_PATH)\n        print_done(f"Built daily sentiment. Rows: {len(df):,}", NEWS_SENTIMENT_PATH)\n        for symbol in ["NVDA", "SPY", "SOXX", "IEF"]:\n            df = clean_and_process_eod(DEFAULT_STOCK_INPUTS[symbol], DEFAULT_STOCK_OUTPUTS[symbol])\n            print_done(f"Processed {symbol} EOD. Rows: {len(df):,}", DEFAULT_STOCK_OUTPUTS[symbol])\n        df = clean_and_process_trends(TRENDS_RAW_PATH, TRENDS_PROCESSED_PATH)\n        print_done(f"Processed trends. Rows: {len(df):,}", TRENDS_PROCESSED_PATH)\n        df = build_model_dataset(output_path=MODEL_DATASET_PATH)\n        print_done(f"Built model dataset. Rows: {len(df):,}; Columns: {len(df.columns):,}", MODEL_DATASET_PATH)\n        validate_dataset(MODEL_DATASET_PATH)\n        write_audit_workbook(MODEL_DATASET_PATH, MODEL_AUDIT_PATH)\n\n\nif __name__ == "__main__":\n    main()\n',
    'clean_analyze': '#!/usr/bin/env python3\n"""Clean and analyze a model dataset for feature selection.\n\nThis combines:\n- clean_model_dataset.py: keep a curated clean feature set and save it.\n- feature_correlation_analysis.py: correlation matrix, high-correlation pairs,\n  target correlations, VIF, and RandomForest feature importance.\n\nExamples:\n  # Clean only\n  python model_dataset_clean_and_analyze.py clean --input data/model_dataset.csv --output data/model_dataset_clean.csv\n\n  # Analyze only\n  python model_dataset_clean_and_analyze.py analyze --input data/model_dataset.csv --plot\n\n  # Clean, then analyze the cleaned output\n  python model_dataset_clean_and_analyze.py all --input data/model_dataset.csv --output data/model_dataset_clean.csv --plot\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nfrom pathlib import Path\nfrom typing import Iterable\n\nimport numpy as np\nimport pandas as pd\n\nDEFAULT_INPUT = "/home/zammorak/thesis/data/model_feed/model_dataset.csv"\nDEFAULT_OUTPUT = "/home/zammorak/thesis/data/model_feed/model_dataset_clean.csv"\n\nFEATURES = [\n    "log_return",\n    "overnight_return",\n    "momentum_5d",\n    "momentum_20d",\n    "volatility_20d",\n    "volume_change",\n    "volume_20d_avg",\n    "avg_sentiment",\n    "sentiment_std",\n    "news_count",\n    "spy_return",\n    "soxx_return",\n    "ief_return",\n    "trends_zscore_30d",\n    "trends_momentum_7d",\n    "trends_spike",\n]\n\nTARGETS = ["target_direction", "target_next_return"]\nMETA = ["date"]\n\n\ndef load_dataset(path: str | Path) -> pd.DataFrame:\n    print(f"Loading dataset: {path}")\n    df = pd.read_csv(path)\n    if "date" in df.columns:\n        df["date"] = pd.to_datetime(df["date"], errors="coerce")\n        df = df.sort_values("date").reset_index(drop=True)\n    return df\n\n\ndef clean_dataset(df: pd.DataFrame, output_path: str | Path) -> pd.DataFrame:\n    """Keep curated metadata, feature, and target columns that exist in the input."""\n    keep_cols = [c for c in META + FEATURES + TARGETS if c in df.columns]\n    clean_df = df[keep_cols].copy()\n\n    print("\\nColumns kept:")\n    for col in clean_df.columns:\n        print(f"  {col}")\n\n    print(f"\\nOriginal shape: {df.shape}")\n    print(f"Clean shape:    {clean_df.shape}")\n\n    output_path = Path(output_path)\n    output_path.parent.mkdir(parents=True, exist_ok=True)\n    clean_df.to_csv(output_path, index=False)\n    print(f"\\nClean dataset saved to:\\n{output_path}")\n\n    return clean_df\n\n\ndef feature_columns(df: pd.DataFrame, extra_drop: Iterable[str] = ()) -> list[str]:\n    drop_cols = set(META + TARGETS + list(extra_drop))\n    return [c for c in df.columns if c not in drop_cols]\n\n\ndef numeric_feature_matrix(df: pd.DataFrame, features: list[str]) -> pd.DataFrame:\n    X = df[features].copy()\n    X = X.apply(pd.to_numeric, errors="coerce")\n    # VIF and RandomForest cannot handle NaN/inf. Median fill keeps rows without lookahead.\n    X = X.replace([np.inf, -np.inf], np.nan)\n    return X.fillna(X.median(numeric_only=True))\n\n\ndef print_high_correlations(corr: pd.DataFrame, threshold: float) -> None:\n    high_corr: list[tuple[str, str, float]] = []\n    for i in range(len(corr.columns)):\n        for j in range(i):\n            value = corr.iloc[i, j]\n            if pd.notna(value) and abs(value) > threshold:\n                high_corr.append((corr.columns[i], corr.columns[j], value))\n\n    print(f"\\nHighly correlated features (>{threshold} absolute correlation):\\n")\n    if not high_corr:\n        print("  None")\n        return\n\n    for f1, f2, value in high_corr:\n        print(f"{f1:25s} {f2:25s} corr={value:.3f}")\n\n\ndef plot_heatmap(corr: pd.DataFrame, output_path: str | Path | None = None, show: bool = False) -> None:\n    import matplotlib.pyplot as plt\n    import seaborn as sns\n\n    plt.figure(figsize=(14, 10))\n    sns.heatmap(corr, cmap="coolwarm", center=0)\n    plt.title("Feature Correlation Matrix")\n    plt.tight_layout()\n\n    if output_path:\n        output_path = Path(output_path)\n        output_path.parent.mkdir(parents=True, exist_ok=True)\n        plt.savefig(output_path, dpi=200)\n        print(f"\\nCorrelation heatmap saved to:\\n{output_path}")\n\n    if show:\n        plt.show()\n    else:\n        plt.close()\n\n\ndef analyze_dataset(\n    df: pd.DataFrame,\n    threshold: float = 0.85,\n    plot: bool = False,\n    heatmap_output: str | Path | None = None,\n    random_state: int = 42,\n) -> None:\n    features = feature_columns(df)\n    X = numeric_feature_matrix(df, features)\n\n    corr = X.corr()\n    print_high_correlations(corr, threshold)\n\n    if plot or heatmap_output:\n        plot_heatmap(corr, output_path=heatmap_output, show=plot)\n\n    if "target_direction" in df.columns:\n        print("\\nCorrelation with target_direction:\\n")\n        target_data = pd.concat([X, pd.to_numeric(df["target_direction"], errors="coerce")], axis=1)\n        target_corr = target_data.corr()["target_direction"].drop("target_direction").sort_values()\n        print(target_corr)\n    else:\n        print("\\nSkipping target correlation: target_direction column not found.")\n\n    try:\n        from statsmodels.stats.outliers_influence import variance_inflation_factor\n\n        print("\\nVariance Inflation Factor (VIF):\\n")\n        vif = pd.DataFrame()\n        vif["feature"] = X.columns\n        vif["VIF"] = [variance_inflation_factor(X.values, i) for i in range(X.shape[1])]\n        print(vif.sort_values("VIF", ascending=False))\n    except Exception as exc:  # noqa: BLE001\n        print(f"\\nSkipping VIF calculation: {exc}")\n\n    if "target_direction" in df.columns:\n        try:\n            from sklearn.ensemble import RandomForestClassifier\n\n            y = pd.to_numeric(df["target_direction"], errors="coerce")\n            valid = y.notna()\n            rf = RandomForestClassifier(n_estimators=500, random_state=random_state)\n            rf.fit(X.loc[valid], y.loc[valid].astype(int))\n\n            print("\\nRandomForest feature importance:\\n")\n            importance = pd.Series(rf.feature_importances_, index=X.columns)\n            print(importance.sort_values(ascending=False))\n        except Exception as exc:  # noqa: BLE001\n            print(f"\\nSkipping RandomForest importance: {exc}")\n\n\ndef parse_args() -> argparse.Namespace:\n    parser = argparse.ArgumentParser(description="Clean and/or analyze a model dataset.")\n    parser.add_argument(\n        "command",\n        choices=["clean", "analyze", "all"],\n        help="clean: save curated columns; analyze: run diagnostics; all: clean then analyze cleaned data.",\n    )\n    parser.add_argument("--input", default=DEFAULT_INPUT, help=f"Input CSV path (default: {DEFAULT_INPUT})")\n    parser.add_argument("--output", default=DEFAULT_OUTPUT, help=f"Clean CSV output path (default: {DEFAULT_OUTPUT})")\n    parser.add_argument("--threshold", type=float, default=0.85, help="High-correlation threshold (default: 0.85)")\n    parser.add_argument("--plot", action="store_true", help="Display the correlation heatmap interactively")\n    parser.add_argument("--heatmap-output", default=None, help="Optional path to save the correlation heatmap image")\n    parser.add_argument("--random-state", type=int, default=42, help="RandomForest random_state (default: 42)")\n    return parser.parse_args()\n\n\ndef main() -> None:\n    args = parse_args()\n    df = load_dataset(args.input)\n\n    if args.command == "clean":\n        clean_dataset(df, args.output)\n    elif args.command == "analyze":\n        analyze_dataset(\n            df,\n            threshold=args.threshold,\n            plot=args.plot,\n            heatmap_output=args.heatmap_output,\n            random_state=args.random_state,\n        )\n    elif args.command == "all":\n        clean_df = clean_dataset(df, args.output)\n        analyze_dataset(\n            clean_df,\n            threshold=args.threshold,\n            plot=args.plot,\n            heatmap_output=args.heatmap_output,\n            random_state=args.random_state,\n        )\n\n\nif __name__ == "__main__":\n    main()\n',
    'lstm_training': '#!/usr/bin/env python3\n"""\nlstm_direction_training_combined.py\n\nUnified ROCm-safe LSTM direction-classifier utility.\n\nCombines:\n- random_search_lstm_direction.py\n- random_search_lstm_direction_v2.py\n- walk_forward_lstm_direction_rocm.py\n\nSubcommands\n-----------\n1) random-search\n   Chronological train/validation/test split, train-only scaling, random\n   hyperparameter search, incremental CSV logging, best model/scaler/meta save,\n   and final test evaluation of the best trial.\n\n2) walk-forward\n   Expanding-window walk-forward backtest with validation threshold selection,\n   per-fold artifacts, out-of-sample prediction CSV, and summary JSON.\n\nROCm note\n---------\nThe model uses LSTM(implementation=1, recurrent_dropout>0) to avoid the fused\nMIOpen/CuDNN path that can fail on ROCm with packed-input errors.\n\nExamples\n--------\nRandom search:\n  HIP_VISIBLE_DEVICES=0 python -u lstm_direction_training_combined.py random-search \\\n    --data /home/zammorak/thesis/data/model_feed/model_dataset_clean.csv \\\n    --outdir /home/zammorak/thesis/models/random_search_direction_v2 \\\n    --trials 50 --auto_threshold\n\nWalk-forward:\n  HIP_VISIBLE_DEVICES=0 python -u lstm_direction_training_combined.py walk-forward \\\n    --data /home/zammorak/thesis/data/model_feed/model_dataset_clean.csv \\\n    --outdir /home/zammorak/thesis/models/walk_forward_direction \\\n    --lookback 60 --initial_train 700 --val_size 126 --test_horizon 63 --step 63 \\\n    --auto_threshold\n"""\n\nfrom __future__ import annotations\n\nimport argparse\nimport json\nimport os\nimport random\nimport time\nfrom dataclasses import dataclass\nfrom typing import Any, Dict, List, Optional, Tuple\n\nimport joblib\nimport numpy as np\nimport pandas as pd\n\n\ndef _set_gpu(gpu_index: Optional[str]) -> None:\n    """Set ROCm GPU visibility before TensorFlow does meaningful GPU work."""\n    if gpu_index is not None:\n        os.environ["HIP_VISIBLE_DEVICES"] = str(gpu_index)\n\n\n# TensorFlow is imported at module load for normal CLI usage. If --gpu is used,\n# HIP_VISIBLE_DEVICES is still set before GPU listing/training in each command.\nimport tensorflow as tf\nfrom tensorflow.keras import callbacks, layers, models\nfrom sklearn.metrics import accuracy_score, confusion_matrix, roc_auc_score\nfrom sklearn.preprocessing import StandardScaler\n\n\nDEFAULT_DATA = "/home/zammorak/thesis/data/model_feed/model_dataset_clean.csv"\n\n\ndef make_sequences(X: np.ndarray, y: np.ndarray, lookback: int) -> Tuple[np.ndarray, np.ndarray]:\n    """Create lookback sequences ending at each time t with label y[t]."""\n    Xs, ys = [], []\n    for i in range(lookback, len(X)):\n        Xs.append(X[i - lookback:i])\n        ys.append(y[i])\n    return np.asarray(Xs, dtype=np.float32), np.asarray(ys, dtype=np.int32)\n\n\ndef build_model(\n    lookback: int,\n    n_features: int,\n    lr: float,\n    lstm_units: int,\n    dropout: float,\n    rec_dropout: float,\n    dense_units: int = 32,\n) -> tf.keras.Model:\n    """Build a ROCm-safe LSTM binary classifier."""\n    model = models.Sequential([\n        layers.Input(shape=(lookback, n_features)),\n        layers.LSTM(\n            lstm_units,\n            dropout=dropout,\n            recurrent_dropout=rec_dropout,\n            implementation=1,\n        ),\n        layers.Dense(dense_units, activation="relu"),\n        layers.Dense(1, activation="sigmoid"),\n    ])\n    model.compile(\n        optimizer=tf.keras.optimizers.Adam(learning_rate=lr),\n        loss="binary_crossentropy",\n        metrics=[tf.keras.metrics.AUC(name="auc"), "accuracy"],\n    )\n    return model\n\n\ndef compute_class_weight(y_train: np.ndarray) -> Optional[Dict[int, float]]:\n    """Balanced class weights, or None if one class is absent."""\n    pos = int(np.sum(y_train == 1))\n    neg = int(np.sum(y_train == 0))\n    if pos == 0 or neg == 0:\n        return None\n    total = pos + neg\n    return {0: float(total / (2 * neg)), 1: float(total / (2 * pos))}\n\n\ndef best_threshold_youden(y_true: np.ndarray, prob: np.ndarray) -> Tuple[float, float]:\n    """Choose threshold by maximizing Youden\'s J = TPR - FPR."""\n    best_t, best_j = 0.5, -1e9\n    for t in np.linspace(0.05, 0.95, 19):\n        pred = (prob >= t).astype(int)\n        tn, fp, fn, tp = confusion_matrix(y_true, pred).ravel()\n        tpr = tp / (tp + fn + 1e-12)\n        fpr = fp / (fp + tn + 1e-12)\n        j = float(tpr - fpr)\n        if j > best_j:\n            best_j, best_t = j, float(t)\n    return best_t, best_j\n\n\ndef eval_auc_acc(y_true: np.ndarray, prob: np.ndarray, threshold: float) -> Tuple[float, float, List[List[int]]]:\n    pred = (prob >= threshold).astype(int)\n    auc = float(roc_auc_score(y_true, prob)) if len(np.unique(y_true)) > 1 else float("nan")\n    acc = float(accuracy_score(y_true, pred))\n    cm = confusion_matrix(y_true, pred).tolist()\n    return auc, acc, cm\n\n\ndef sharpe_ratio(daily_returns: np.ndarray) -> float:\n    daily_returns = np.asarray(daily_returns, dtype=float)\n    std = daily_returns.std()\n    if std == 0:\n        return float("nan")\n    return float(daily_returns.mean() / std * np.sqrt(252))\n\n\ndef load_direction_dataset(path: str, require_date: bool = False) -> Tuple[pd.DataFrame, pd.DataFrame, np.ndarray, np.ndarray]:\n    df = pd.read_csv(path)\n    if "date" in df.columns:\n        df["date"] = pd.to_datetime(df["date"])\n        df = df.sort_values("date").reset_index(drop=True)\n    elif require_date:\n        raise ValueError("Expected a \'date\' column in dataset.")\n\n    if "target_direction" not in df.columns:\n        raise ValueError("target_direction missing in dataset.")\n\n    drop_cols = {"date", "target_next_return", "target_direction"}\n    feature_cols = [c for c in df.columns if c not in drop_cols]\n    X_df = df[feature_cols].select_dtypes(include=[np.number]).copy()\n    if X_df.shape[1] == 0:\n        raise ValueError("No numeric features found after dropping meta/targets.")\n\n    X_all = X_df.to_numpy()\n    y_all = df["target_direction"].astype(int).to_numpy()\n    return df, X_df, X_all, y_all\n\n\n@dataclass\nclass TrialResult:\n    trial: int\n    val_auc: float\n    val_acc: float\n    threshold: float\n    youden_j: Optional[float]\n    best_epoch: int\n    best_val_auc_in_training: float\n    best_val_loss_in_training: float\n    seconds: float\n    lookback: int\n    lstm_units: int\n    dropout: float\n    recurrent_dropout: float\n    lr: float\n    batch: int\n    dense_units: int\n\n\ndef sample_params(rng: random.Random, space: str = "v2") -> Dict[str, Any]:\n    """Sample hyperparameters. `v1` matches the earlier script; `v2` adds dense_units."""\n    params: Dict[str, Any] = {\n        "lookback": rng.choice([45, 60, 75, 90, 105]),\n        "lstm_units": rng.choice([16, 32, 48, 64]),\n        "dropout": rng.choice([0.02, 0.05, 0.08, 0.10]),\n        "recurrent_dropout": rng.choice([0.15, 0.20, 0.25]),\n        "lr": rng.choice([1e-4, 2e-4, 3e-4]),\n        "batch": rng.choice([16, 32, 64]),\n    }\n    params["dense_units"] = rng.choice([16, 32, 64]) if space == "v2" else 32\n    return params\n\n\ndef run_random_search(args: argparse.Namespace) -> None:\n    _set_gpu(args.gpu)\n    os.makedirs(args.outdir, exist_ok=True)\n\n    results_csv = os.path.join(args.outdir, "random_search_results.csv")\n    best_dir = os.path.join(args.outdir, "best")\n    os.makedirs(best_dir, exist_ok=True)\n\n    rng = random.Random(args.seed)\n    np.random.seed(args.seed)\n    tf.random.set_seed(args.seed)\n\n    df, X_df, X_all, y_all = load_direction_dataset(args.data)\n    n = len(df)\n    if args.test_size + args.val_size + 10 >= n:\n        raise ValueError("Not enough rows for chosen val/test sizes.")\n\n    test_start = n - args.test_size\n    val_start = test_start - args.val_size\n\n    scaler = StandardScaler()\n    X_train_scaled = scaler.fit_transform(X_all[:val_start])\n    X_val_scaled = scaler.transform(X_all[val_start:test_start])\n    X_test_scaled = scaler.transform(X_all[test_start:])\n    X_scaled_full = np.vstack([X_train_scaled, X_val_scaled, X_test_scaled]).astype(np.float32)\n\n    best_val_auc = -1.0\n    best_payload: Optional[Dict[str, Any]] = None\n    trial_rows: List[Dict[str, Any]] = []\n\n    print("=== RANDOM SEARCH LSTM (ROCm-safe) ===", flush=True)\n    print("TF GPUs:", tf.config.list_physical_devices("GPU"), flush=True)\n    print("Dataset rows:", n, "| features:", X_df.shape[1], flush=True)\n    print("Split sizes -> train:", val_start, "val:", args.val_size, "test:", args.test_size, flush=True)\n\n    for trial in range(1, args.trials + 1):\n        params = sample_params(rng, args.search_space)\n        lookback = int(params["lookback"])\n\n        if args.test_size + args.val_size + lookback >= n:\n            continue\n\n        X_seq, y_seq = make_sequences(X_scaled_full, y_all, lookback)\n        seq_val_start = val_start - lookback\n        seq_test_start = test_start - lookback\n\n        X_train, y_train = X_seq[:seq_val_start], y_seq[:seq_val_start]\n        X_val, y_val = X_seq[seq_val_start:seq_test_start], y_seq[seq_val_start:seq_test_start]\n\n        model = build_model(\n            lookback=lookback,\n            n_features=X_train.shape[-1],\n            lr=float(params["lr"]),\n            lstm_units=int(params["lstm_units"]),\n            dropout=float(params["dropout"]),\n            rec_dropout=float(params["recurrent_dropout"]),\n            dense_units=int(params["dense_units"]),\n        )\n\n        cb = [\n            callbacks.EarlyStopping(monitor="val_auc", mode="max", patience=args.patience, restore_best_weights=True),\n            callbacks.ReduceLROnPlateau(\n                monitor="val_auc", mode="max", patience=max(2, args.patience // 2), factor=0.5, min_lr=1e-5\n            ),\n        ]\n\n        t0 = time.time()\n        hist = model.fit(\n            X_train,\n            y_train,\n            validation_data=(X_val, y_val),\n            epochs=args.max_epochs,\n            batch_size=int(params["batch"]),\n            verbose=args.verbose,\n            callbacks=cb,\n            class_weight=compute_class_weight(y_train),\n        )\n        seconds = time.time() - t0\n\n        val_prob = model.predict(X_val, verbose=0).reshape(-1)\n        val_auc = float(roc_auc_score(y_val, val_prob)) if len(np.unique(y_val)) > 1 else float("nan")\n\n        if args.auto_threshold:\n            thr, j = best_threshold_youden(y_val, val_prob)\n        else:\n            thr, j = 0.5, None\n\n        _, val_acc, val_cm = eval_auc_acc(y_val, val_prob, thr)\n        best_val_auc_in_training = float(np.max(hist.history.get("val_auc", [np.nan])))\n        best_val_loss_in_training = float(np.min(hist.history.get("val_loss", [np.nan])))\n        best_epoch = int(np.argmax(hist.history.get("val_auc", [val_auc])) + 1)\n\n        row = TrialResult(\n            trial=trial,\n            val_auc=val_auc,\n            val_acc=val_acc,\n            threshold=float(thr),\n            youden_j=(float(j) if j is not None else None),\n            best_epoch=best_epoch,\n            best_val_auc_in_training=best_val_auc_in_training,\n            best_val_loss_in_training=best_val_loss_in_training,\n            seconds=float(seconds),\n            lookback=lookback,\n            lstm_units=int(params["lstm_units"]),\n            dropout=float(params["dropout"]),\n            recurrent_dropout=float(params["recurrent_dropout"]),\n            lr=float(params["lr"]),\n            batch=int(params["batch"]),\n            dense_units=int(params["dense_units"]),\n        ).__dict__\n        row["val_cm_tn_fp_fn_tp"] = val_cm\n        trial_rows.append(row)\n        pd.DataFrame(trial_rows).to_csv(results_csv, index=False)\n\n        if np.isfinite(val_auc) and val_auc > best_val_auc:\n            best_val_auc = val_auc\n            best_payload = {\n                "best_trial": trial,\n                "params": params,\n                "val_auc": float(val_auc),\n                "val_acc": float(val_acc),\n                "threshold": float(thr),\n                "youden_j": (float(j) if j is not None else None),\n                "feature_cols": X_df.columns.tolist(),\n                "hip_visible_devices": os.environ.get("HIP_VISIBLE_DEVICES", None),\n            }\n            model.save(os.path.join(best_dir, "model.keras"))\n            joblib.dump(scaler, os.path.join(best_dir, "scaler.joblib"))\n            with open(os.path.join(best_dir, "meta.json"), "w") as f:\n                json.dump(best_payload, f, indent=2)\n\n        if args.save_within > 0 and np.isfinite(val_auc) and best_val_auc > 0:\n            if val_auc >= (best_val_auc - float(args.save_within)):\n                close_dir = os.path.join(args.outdir, f"top_trial_{trial:03d}_auc_{val_auc:.4f}")\n                os.makedirs(close_dir, exist_ok=True)\n                model.save(os.path.join(close_dir, "model.keras"))\n\n        print(\n            f"[{trial:03d}/{args.trials}] val_auc={val_auc:.4f} val_acc={val_acc:.4f} "\n            f"thr={thr:.2f} lb={lookback} units={params[\'lstm_units\']} dense={params[\'dense_units\']} "\n            f"lr={params[\'lr\']} drop={params[\'dropout\']} rdrop={params[\'recurrent_dropout\']} batch={params[\'batch\']}",\n            flush=True,\n        )\n        tf.keras.backend.clear_session()\n\n    print("\\nRandom search complete.", flush=True)\n    print("Results CSV:", results_csv, flush=True)\n\n    if best_payload is None:\n        print("No valid trials produced a best model.", flush=True)\n        return\n\n    best_params = best_payload["params"]\n    lb = int(best_params["lookback"])\n    X_seq, y_seq = make_sequences(X_scaled_full, y_all, lb)\n    seq_test_start = test_start - lb\n    X_test = X_seq[seq_test_start:]\n    y_test = y_seq[seq_test_start:]\n\n    best_model = tf.keras.models.load_model(os.path.join(best_dir, "model.keras"))\n    test_prob = best_model.predict(X_test, verbose=0).reshape(-1)\n    thr = float(best_payload.get("threshold", 0.5))\n    test_auc, test_acc, test_cm = eval_auc_acc(y_test, test_prob, thr)\n\n    best_payload.update({\n        "test_auc": float(test_auc),\n        "test_acc": float(test_acc),\n        "test_cm_tn_fp_fn_tp": test_cm,\n        "evaluated_at": time.strftime("%Y-%m-%d %H:%M:%S"),\n    })\n    with open(os.path.join(best_dir, "meta.json"), "w") as f:\n        json.dump(best_payload, f, indent=2)\n\n    print("\\nBEST MODEL", flush=True)\n    print("  val_auc:", best_payload["val_auc"], "| val_acc:", best_payload["val_acc"], "| thr:", thr, flush=True)\n    print("  test_auc:", test_auc, "| test_acc:", test_acc, "| test_cm:", test_cm, flush=True)\n    print("Best artifacts saved in:", best_dir, flush=True)\n\n\ndef run_walk_forward(args: argparse.Namespace) -> None:\n    _set_gpu(args.gpu)\n    os.makedirs(args.outdir, exist_ok=True)\n\n    print("=== WALK-FORWARD LSTM (ROCm-safe) ===", flush=True)\n    print("Data   :", args.data, flush=True)\n    print("Outdir :", args.outdir, flush=True)\n    print("HIP_VISIBLE_DEVICES:", os.environ.get("HIP_VISIBLE_DEVICES", None), flush=True)\n    print("TF GPUs:", tf.config.list_physical_devices("GPU"), flush=True)\n\n    df, X_df, X_all, y_all = load_direction_dataset(args.data, require_date=True)\n    n = len(df)\n    print(\n        f"Rows={n} | Features={X_df.shape[1]} | Range={df[\'date\'].iloc[0].date()}→{df[\'date\'].iloc[-1].date()}",\n        flush=True,\n    )\n\n    if args.initial_train + args.test_horizon + args.lookback >= n:\n        raise ValueError(\n            f"Not enough rows for settings: initial_train({args.initial_train}) + "\n            f"test_horizon({args.test_horizon}) + lookback({args.lookback}) >= n({n})."\n        )\n\n    oos_records: List[pd.DataFrame] = []\n    fold_summaries: List[Dict[str, Any]] = []\n    fold = 0\n    train_end = args.initial_train\n\n    while True:\n        test_end = train_end + args.test_horizon\n        if test_end > n:\n            break\n\n        fold += 1\n        fold_dir = os.path.join(args.outdir, f"fold_{fold:02d}")\n        os.makedirs(fold_dir, exist_ok=True)\n\n        val_start = train_end - args.val_size\n        if val_start <= args.lookback:\n            raise ValueError("val_size too large for the current fold given lookback.")\n\n        scaler = StandardScaler()\n        X_train_fit = scaler.fit_transform(X_all[:val_start])\n        X_val_part = scaler.transform(X_all[val_start:train_end])\n        X_test_part = scaler.transform(X_all[train_end:test_end])\n\n        X_scaled_concat = np.vstack([X_train_fit, X_val_part, X_test_part]).astype(np.float32)\n        y_concat = np.concatenate([y_all[:val_start], y_all[val_start:train_end], y_all[train_end:test_end]])\n\n        X_seq, y_seq = make_sequences(X_scaled_concat, y_concat, args.lookback)\n        seq_val_start = val_start - args.lookback\n        seq_test_start = train_end - args.lookback\n\n        X_train, y_train = X_seq[:seq_val_start], y_seq[:seq_val_start]\n        X_val, y_val = X_seq[seq_val_start:seq_test_start], y_seq[seq_val_start:seq_test_start]\n        X_test, y_test = X_seq[seq_test_start:], y_seq[seq_test_start:]\n\n        print(\n            f"\\n[fold {fold:02d}] train_end={train_end} ({df[\'date\'].iloc[train_end-1].date()}) | "\n            f"test={df[\'date\'].iloc[train_end].date()}→{df[\'date\'].iloc[test_end-1].date()} | "\n            f"shapes train={X_train.shape} val={X_val.shape} test={X_test.shape}",\n            flush=True,\n        )\n\n        model = build_model(\n            lookback=args.lookback,\n            n_features=X_train.shape[-1],\n            lr=args.lr,\n            lstm_units=args.lstm_units,\n            dropout=args.dropout,\n            rec_dropout=args.recurrent_dropout,\n            dense_units=args.dense_units,\n        )\n        cb = [\n            callbacks.EarlyStopping(monitor="val_auc", mode="max", patience=args.patience, restore_best_weights=True),\n            callbacks.ReduceLROnPlateau(monitor="val_auc", mode="max", patience=max(2, args.patience // 2), factor=0.5, min_lr=1e-5),\n        ]\n\n        t0 = time.time()\n        model.fit(\n            X_train,\n            y_train,\n            validation_data=(X_val, y_val),\n            epochs=args.epochs,\n            batch_size=args.batch,\n            verbose=args.verbose,\n            callbacks=cb,\n            class_weight=compute_class_weight(y_train),\n        )\n        train_seconds = time.time() - t0\n\n        val_prob = model(X_val, training=False).numpy().reshape(-1)\n        val_auc = float(roc_auc_score(y_val, val_prob)) if len(np.unique(y_val)) > 1 else float("nan")\n        if args.auto_threshold:\n            thr, j = best_threshold_youden(y_val, val_prob)\n        else:\n            thr, j = float(args.threshold), None\n        val_pred = (val_prob >= thr).astype(int)\n        val_acc = float(accuracy_score(y_val, val_pred))\n\n        test_prob = model(X_test, training=False).numpy().reshape(-1)\n        test_auc = float(roc_auc_score(y_test, test_prob)) if len(np.unique(y_test)) > 1 else float("nan")\n        test_pred = (test_prob >= thr).astype(int)\n        test_acc = float(accuracy_score(y_test, test_pred))\n        test_cm = confusion_matrix(y_test, test_pred).tolist()\n\n        model.save(os.path.join(fold_dir, "model.keras"))\n        joblib.dump(scaler, os.path.join(fold_dir, "scaler.joblib"))\n\n        meta = {\n            "fold": fold,\n            "train_end_date": str(df["date"].iloc[train_end - 1].date()),\n            "test_start_date": str(df["date"].iloc[train_end].date()),\n            "test_end_date": str(df["date"].iloc[test_end - 1].date()),\n            "val_auc": val_auc,\n            "val_acc": val_acc,\n            "threshold": thr,\n            "youden_j": j,\n            "test_auc": test_auc,\n            "test_acc": test_acc,\n            "test_cm": test_cm,\n            "train_seconds": train_seconds,\n            "params": {\n                "lookback": args.lookback,\n                "lstm_units": args.lstm_units,\n                "dense_units": args.dense_units,\n                "lr": args.lr,\n                "dropout": args.dropout,\n                "recurrent_dropout": args.recurrent_dropout,\n                "batch": args.batch,\n                "epochs": args.epochs,\n            },\n        }\n        with open(os.path.join(fold_dir, "meta.json"), "w") as f:\n            json.dump(meta, f, indent=2)\n        fold_summaries.append(meta)\n\n        test_dates = df["date"].iloc[train_end:test_end].reset_index(drop=True)\n        if len(test_dates) != len(y_test):\n            test_dates = test_dates.iloc[-len(y_test):].reset_index(drop=True)\n\n        out = pd.DataFrame({\n            "fold": fold,\n            "date": test_dates,\n            "y_true": y_test,\n            "y_prob_up": test_prob,\n            "y_pred": test_pred,\n            "threshold": thr,\n        })\n        if "target_next_return" in df.columns:\n            next_ret = df["target_next_return"].iloc[train_end:test_end].reset_index(drop=True)\n            if len(next_ret) != len(y_test):\n                next_ret = next_ret.iloc[-len(y_test):].reset_index(drop=True)\n            out["target_next_return"] = next_ret.values\n\n        oos_records.append(out)\n        print(\n            f"[fold {fold:02d} DONE] VAL auc={val_auc:.4f} acc={val_acc:.4f} thr={thr:.2f} | "\n            f"TEST auc={test_auc:.4f} acc={test_acc:.4f} cm={test_cm}",\n            flush=True,\n        )\n\n        train_end += args.step\n        tf.keras.backend.clear_session()\n\n    if not oos_records:\n        raise RuntimeError("No walk-forward folds were produced. Check initial_train/test_horizon/step settings.")\n\n    oos = pd.concat(oos_records, ignore_index=True).sort_values("date").reset_index(drop=True)\n    oos_path = os.path.join(args.outdir, "walk_forward_oos_predictions.csv")\n    oos.to_csv(oos_path, index=False)\n\n    overall_auc = float(roc_auc_score(oos["y_true"], oos["y_prob_up"])) if len(np.unique(oos["y_true"])) > 1 else float("nan")\n    overall_acc = float(accuracy_score(oos["y_true"], oos["y_pred"]))\n    overall_cm = confusion_matrix(oos["y_true"], oos["y_pred"]).tolist()\n\n    strat: Dict[str, float] = {}\n    if "target_next_return" in oos.columns:\n        strategy_returns = oos["target_next_return"].values * oos["y_pred"].values\n        strat = {\n            "sharpe_long_only": sharpe_ratio(strategy_returns),\n            "avg_daily_return_long_only": float(np.mean(strategy_returns)),\n            "trade_rate_long_only": float(np.mean(oos["y_pred"].values)),\n        }\n\n    summary = {\n        "overall": {"auc": overall_auc, "acc": overall_acc, "cm": overall_cm, "strategy": strat},\n        "folds": fold_summaries,\n        "saved_predictions": oos_path,\n        "hip_visible_devices": os.environ.get("HIP_VISIBLE_DEVICES", None),\n        "feature_count": int(X_df.shape[1]),\n    }\n    with open(os.path.join(args.outdir, "walk_forward_summary.json"), "w") as f:\n        json.dump(summary, f, indent=2)\n\n    print("\\n=== DONE ===", flush=True)\n    print("OOS predictions:", oos_path, flush=True)\n    print("Overall OOS AUC:", overall_auc, flush=True)\n    print("Overall OOS ACC:", overall_acc, flush=True)\n    if strat:\n        print("OOS Sharpe (long-only):", strat["sharpe_long_only"], flush=True)\n        print("Trade rate:", strat["trade_rate_long_only"], flush=True)\n\n\ndef build_parser() -> argparse.ArgumentParser:\n    parser = argparse.ArgumentParser(description="Unified ROCm-safe LSTM direction training/backtesting CLI.")\n    sub = parser.add_subparsers(dest="command", required=True)\n\n    rs = sub.add_parser("random-search", help="Run chronological random hyperparameter search.")\n    rs.add_argument("--data", default=DEFAULT_DATA, help="Clean dataset path.")\n    rs.add_argument("--outdir", default="/home/zammorak/thesis/models/random_search_direction_v2")\n    rs.add_argument("--val_size", type=int, default=126)\n    rs.add_argument("--test_size", type=int, default=252)\n    rs.add_argument("--trials", type=int, default=50)\n    rs.add_argument("--max_epochs", type=int, default=50)\n    rs.add_argument("--patience", type=int, default=6)\n    rs.add_argument("--seed", type=int, default=1337)\n    rs.add_argument("--gpu", default=None, help="AMD GPU index for HIP_VISIBLE_DEVICES, e.g. 0")\n    rs.add_argument("--auto_threshold", action="store_true", help="Select threshold per trial on validation via Youden J.")\n    rs.add_argument("--save_within", type=float, default=0.01, help="Save trial models within this AUC of best; 0 disables.")\n    rs.add_argument("--search_space", choices=["v1", "v2"], default="v2", help="v1 uses fixed dense=32; v2 samples dense units.")\n    rs.add_argument("--verbose", type=int, default=0, help="Keras fit verbosity.")\n    rs.set_defaults(func=run_random_search)\n\n    wf = sub.add_parser("walk-forward", help="Run expanding-window walk-forward backtest.")\n    wf.add_argument("--data", default=DEFAULT_DATA)\n    wf.add_argument("--outdir", default="/home/zammorak/thesis/models/walk_forward_direction")\n    wf.add_argument("--lookback", type=int, default=60)\n    wf.add_argument("--initial_train", type=int, default=700)\n    wf.add_argument("--val_size", type=int, default=126)\n    wf.add_argument("--test_horizon", type=int, default=63)\n    wf.add_argument("--step", type=int, default=63)\n    wf.add_argument("--epochs", type=int, default=30)\n    wf.add_argument("--batch", type=int, default=32)\n    wf.add_argument("--lr", type=float, default=2e-4)\n    wf.add_argument("--lstm_units", type=int, default=32)\n    wf.add_argument("--dense_units", type=int, default=64)\n    wf.add_argument("--dropout", type=float, default=0.05)\n    wf.add_argument("--recurrent_dropout", type=float, default=0.2)\n    wf.add_argument("--patience", type=int, default=6)\n    wf.add_argument("--auto_threshold", action="store_true")\n    wf.add_argument("--threshold", type=float, default=0.5)\n    wf.add_argument("--gpu", default=None)\n    wf.add_argument("--verbose", type=int, default=1, help="Keras fit verbosity.")\n    wf.set_defaults(func=run_walk_forward)\n\n    return parser\n\n\ndef main() -> None:\n    parser = build_parser()\n    args = parser.parse_args()\n    args.func(args)\n\n\nif __name__ == "__main__":\n    main()\n',
    'lstm_basic': '#!/usr/bin/env python3\n"""LSTM binary classification: predict next-day direction (target_direction).\n\nIMPORTANT (ROCm / MIOpen):\n- This script forces the non-fused Keras LSTM implementation to avoid the ROCm MIOpen error:\n  "ROCm MIOpen only supports packed input output." from CudnnRNNV3.\n- We do this by setting: implementation=1 and recurrent_dropout>0, which prevents the fused path.\n\nGPU selection:\n- Use HIP_VISIBLE_DEVICES to pick your dedicated AMD GPU.\n  Example: HIP_VISIBLE_DEVICES=0 python script.py ...\n"""\n\nimport os\nimport json\nimport argparse\nimport numpy as np\nimport pandas as pd\n\ndef _set_gpu(gpu_index):\n    if gpu_index is not None:\n        os.environ["HIP_VISIBLE_DEVICES"] = str(gpu_index)\n\nimport tensorflow as tf\nfrom tensorflow.keras import layers, models, callbacks\nfrom sklearn.preprocessing import StandardScaler\nfrom sklearn.metrics import accuracy_score, roc_auc_score, confusion_matrix\nimport joblib\n\n\ndef make_sequences(X, y, lookback: int):\n    Xs, ys = [], []\n    for i in range(lookback, len(X)):\n        Xs.append(X[i - lookback:i])\n        ys.append(y[i])\n    return np.asarray(Xs), np.asarray(ys)\n\n\ndef build_model(lookback, n_features, lr, lstm_units, dropout, rec_dropout):\n    model = models.Sequential([\n        layers.Input(shape=(lookback, n_features)),\n        layers.LSTM(\n            lstm_units,\n            dropout=dropout,\n            recurrent_dropout=rec_dropout,\n            implementation=1,  # ROCm-safe (non-fused)\n        ),\n        layers.Dense(32, activation="relu"),\n        layers.Dense(1, activation="sigmoid"),\n    ])\n    model.compile(\n        optimizer=tf.keras.optimizers.Adam(learning_rate=lr),\n        loss="binary_crossentropy",\n        metrics=["accuracy", tf.keras.metrics.AUC(name="auc")]\n    )\n    return model\n\n\ndef sharpe_ratio(returns: np.ndarray):\n    std = np.std(returns)\n    if std == 0:\n        return float("nan")\n    return float(np.mean(returns) / std * np.sqrt(252))\n\n\ndef compute_class_weight(y_train: np.ndarray):\n    pos = int(np.sum(y_train == 1))\n    neg = int(np.sum(y_train == 0))\n    if pos == 0 or neg == 0:\n        return None\n    return {0: float((pos + neg) / (2 * neg)), 1: float((pos + neg) / (2 * pos))}\n\n\ndef best_threshold_from_val(y_val: np.ndarray, val_prob: np.ndarray):\n    """Pick threshold using Youden\'s J (TPR - FPR) on the validation set."""\n    best_t, best_j = 0.5, -1e9\n    for t in np.linspace(0.05, 0.95, 19):\n        val_pred = (val_prob >= t).astype(int)\n        tn, fp, fn, tp = confusion_matrix(y_val, val_pred).ravel()\n        tpr = tp / (tp + fn + 1e-12)\n        fpr = fp / (fp + tn + 1e-12)\n        j = tpr - fpr\n        if j > best_j:\n            best_j, best_t = float(j), float(t)\n    return best_t, best_j\n\n\ndef eval_split(name: str, y_true: np.ndarray, y_prob: np.ndarray, threshold: float):\n    y_pred = (y_prob >= threshold).astype(int)\n    acc = float(accuracy_score(y_true, y_pred))\n    auc = float(roc_auc_score(y_true, y_prob)) if len(np.unique(y_true)) > 1 else float("nan")\n    cm = confusion_matrix(y_true, y_pred).tolist()\n    print(f"\\\\n{name} Accuracy: {acc}")\n    print(f"{name} AUC: {auc}")\n    print(f"{name} Confusion matrix [[TN,FP],[FN,TP]]: {cm}")\n    print(f"{name} prob stats: min={float(np.min(y_prob)):.4f} mean={float(np.mean(y_prob)):.4f} max={float(np.max(y_prob)):.4f}")\n    return {"accuracy": acc, "auc": auc, "confusion_matrix": cm}\n\n\ndef main():\n    ap = argparse.ArgumentParser()\n\n    ap.add_argument(\n        "--data",\n        default="/home/zammorak/thesis/data/model_feed/model_dataset_clean.csv",\n        help="Path to model_dataset.csv",\n    )\n    ap.add_argument(\n        "--outdir",\n        default="/home/zammorak/thesis/models",\n        help="Output directory for model + artifacts",\n    )\n\n    ap.add_argument("--lookback", type=int, default=30)\n    ap.add_argument("--val_size", type=int, default=126)\n    ap.add_argument("--test_size", type=int, default=252)\n\n    ap.add_argument("--epochs", type=int, default=50)\n    ap.add_argument("--batch", type=int, default=32)\n    ap.add_argument("--lr", type=float, default=1e-3)\n\n    ap.add_argument("--lstm_units", type=int, default=64)\n    ap.add_argument("--dropout", type=float, default=0.1)\n    ap.add_argument("--recurrent_dropout", type=float, default=0.2)\n\n    ap.add_argument("--gpu", default=None, help="AMD GPU index for HIP_VISIBLE_DEVICES (e.g., 0)")\n\n    ap.add_argument("--threshold", type=float, default=0.45, help="Decision threshold if --auto_threshold is not used")\n    ap.add_argument("--auto_threshold", action="store_true", help="Choose threshold using validation set (Youden\'s J)")\n\n    args = ap.parse_args()\n\n    _set_gpu(args.gpu)\n    os.makedirs(args.outdir, exist_ok=True)\n\n    df = pd.read_csv(args.data)\n    df["date"] = pd.to_datetime(df["date"])\n    df = df.sort_values("date").reset_index(drop=True)\n\n    if "target_direction" not in df.columns:\n        raise ValueError("target_direction missing.")\n\n    # --- Features / target ---\n    drop_cols = {"date", "target_next_return", "target_direction"}\n    feature_cols = [c for c in df.columns if c not in drop_cols]\n    X_df = df[feature_cols].select_dtypes(include=[np.number]).copy()\n    if X_df.shape[1] == 0:\n        raise ValueError("No numeric feature columns found after filtering.")\n\n    X_all = X_df.to_numpy()\n    y_all = df["target_direction"].astype(int).to_numpy()\n\n    # --- Time split (train | val | test) ---\n    n = len(df)\n    if args.test_size + args.val_size + args.lookback >= n:\n        raise ValueError("Not enough rows for chosen lookback/val/test sizes.")\n\n    test_start = n - args.test_size\n    val_start = test_start - args.val_size\n\n    # --- Scale with train only ---\n    scaler = StandardScaler()\n    X_train_scaled = scaler.fit_transform(X_all[:val_start])\n    X_val_scaled = scaler.transform(X_all[val_start:test_start])\n    X_test_scaled = scaler.transform(X_all[test_start:])\n    X_scaled = np.vstack([X_train_scaled, X_val_scaled, X_test_scaled])\n\n    # --- Make sequences ---\n    X_seq, y_seq = make_sequences(X_scaled, y_all, args.lookback)\n    seq_val_start = val_start - args.lookback\n    seq_test_start = test_start - args.lookback\n\n    X_train, y_train = X_seq[:seq_val_start], y_seq[:seq_val_start]\n    X_val, y_val = X_seq[seq_val_start:seq_test_start], y_seq[seq_val_start:seq_test_start]\n    X_test, y_test = X_seq[seq_test_start:], y_seq[seq_test_start:]\n\n    print("TF GPUs:", tf.config.list_physical_devices("GPU"))\n    print("Shapes:", X_train.shape, X_val.shape, X_test.shape)\n\n    model = build_model(\n        args.lookback, X_train.shape[-1], args.lr, args.lstm_units, args.dropout, args.recurrent_dropout\n    )\n\n    cb = [\n        callbacks.EarlyStopping(monitor="val_loss", patience=8, restore_best_weights=True),\n        callbacks.ReduceLROnPlateau(monitor="val_loss", patience=4, factor=0.5, min_lr=1e-5),\n    ]\n\n    class_weight = compute_class_weight(y_train)\n    if class_weight is not None:\n        print("class_weight:", class_weight)\n\n    model.fit(\n        X_train, y_train,\n        validation_data=(X_val, y_val),\n        epochs=args.epochs,\n        batch_size=args.batch,\n        callbacks=cb,\n        verbose=1,\n        class_weight=class_weight\n    )\n\n    # --- Validation probabilities + threshold selection ---\n    val_prob = model.predict(X_val).reshape(-1)\n    if args.auto_threshold:\n        t, j = best_threshold_from_val(y_val, val_prob)\n        print(f"\\\\nAuto threshold from validation: t={t:.2f} (Youden J={j:.4f})")\n        threshold = t\n    else:\n        threshold = float(args.threshold)\n\n    # --- Evaluate on validation + test ---\n    val_metrics = eval_split("VAL", y_val, val_prob, threshold)\n\n    test_prob = model.predict(X_test).reshape(-1)\n    test_metrics = eval_split("TEST", y_test, test_prob, threshold)\n    test_pred = (test_prob >= threshold).astype(int)\n\n    # --- Simple strategy metric if next return is available ---\n    strat = {}\n    if "target_next_return" in df.columns:\n        test_returns = df["target_next_return"].iloc[test_start:].to_numpy()\n        if len(test_returns) != len(y_test):\n            test_returns = test_returns[-len(y_test):]\n        strategy_returns = test_returns * test_pred\n        strat = {\n            "sharpe_long_only": sharpe_ratio(strategy_returns),\n            "avg_daily_return_long_only": float(np.mean(strategy_returns)),\n        }\n        print("\\\\nStrategy Sharpe (long when up):", strat["sharpe_long_only"])\n\n    # --- Save artifacts ---\n    model_path = os.path.join(args.outdir, "lstm_direction_model.keras")\n    scaler_path = os.path.join(args.outdir, "lstm_direction_scaler.joblib")\n    meta_path = os.path.join(args.outdir, "lstm_direction_meta.json")\n    pred_path = os.path.join(args.outdir, "lstm_direction_predictions.csv")\n\n    model.save(model_path)\n    joblib.dump(scaler, scaler_path)\n\n    test_dates = df["date"].iloc[test_start:].reset_index(drop=True)\n    if len(test_dates) != len(y_test):\n        test_dates = test_dates.iloc[-len(y_test):].reset_index(drop=True)\n\n    pd.DataFrame({\n        "date": test_dates,\n        "y_true": y_test,\n        "y_prob_up": test_prob,\n        "y_pred": test_pred\n    }).to_csv(pred_path, index=False)\n\n    meta = {\n        "task": "direction_classification",\n        "target": "target_direction",\n        "lookback": args.lookback,\n        "val_size": args.val_size,\n        "test_size": args.test_size,\n        "threshold_used": threshold,\n        "auto_threshold": bool(args.auto_threshold),\n        "feature_cols": X_df.columns.tolist(),\n        "val_metrics": val_metrics,\n        "test_metrics": test_metrics,\n        "strategy": strat,\n        "hip_visible_devices": os.environ.get("HIP_VISIBLE_DEVICES", None),\n        "lstm": {"implementation": 1, "dropout": args.dropout, "recurrent_dropout": args.recurrent_dropout},\n    }\n    with open(meta_path, "w") as f:\n        json.dump(meta, f, indent=2)\n\n    print("\\\\nSaved:")\n    print("  model:", model_path)\n    print("  scaler:", scaler_path)\n    print("  meta :", meta_path)\n    print("  preds:", pred_path)\n\n\nif __name__ == "__main__":\n    main()\n',
    'minute_preprocess': '#!/usr/bin/env python3\n"""\nFast, type-checker-friendly expansion of a nested \'data\' column from a Parquet file.\n- Loads the raw parquet\n- Expands dicts from the \'data\' column (using from_records for Pylance friendliness)\n- Parses date (UTC) and optionally converts to Europe/Amsterdam\n- Sets a DatetimeIndex\n- Saves an expanded parquet (creating directories if needed)\n- Prints quick sanity checks + timing breakdown\n"""\n\nimport time\nfrom pathlib import Path\nfrom typing import Any, Dict, List, Optional\n\nimport pandas as pd\n\n# --- settings ---\nINFILE: str = "/home/zammorak/thesis-starter/thesis/data/raw/minute/NVDA/NVDA_2025-09-26_to_2025-10-02.parquet"\nOUTFILE: str = "/home/zammorak/thesis-starter/thesis/data/processed/minute/NVDA/NVDA_2025-09-26_to_2025-10-02_expanded.parquet"\nCONVERT_TO_AMS: bool = False  # set True if you want local Amsterdam time\n\n\ndef expand_data_column(df: pd.DataFrame, data_col: str = "data") -> pd.DataFrame:\n    """Expand a column of dicts into flat columns (type-checker friendly)."""\n    if data_col not in df.columns:\n        return df\n    # Convert Series[dict] -> list[dict] to satisfy static type checkers\n    records: List[Dict[str, Any]] = df[data_col].tolist()\n    expanded = pd.DataFrame.from_records(records)\n    return df.drop(columns=[data_col]).join(expanded)\n\n\ndef coerce_dtypes(df: pd.DataFrame) -> pd.DataFrame:\n    """Coerce common OHLCV + flags to sensible dtypes, if present."""\n    float_cols = [c for c in ("open", "high", "low", "close") if c in df.columns]\n    int_cols = [c for c in ("volume",) if c in df.columns]\n    bool_cols = [c for c in ("is_extended_hours",) if c in df.columns]\n\n    for c in float_cols:\n        df[c] = pd.to_numeric(df[c], errors="coerce")\n\n    for c in int_cols:\n        # Nullable Int64 handles missing values gracefully\n        df[c] = pd.to_numeric(df[c], errors="coerce").astype("Int64")\n\n    for c in bool_cols:\n        if df[c].dtype != "bool" and df[c].dtype.name != "boolean":\n            # \'boolean\' is pandas\' nullable boolean\n            df[c] = df[c].astype("boolean")\n\n    return df\n\n\ndef parse_and_index_date(\n    df: pd.DataFrame, date_col: str = "date", to_ams: bool = False\n) -> pd.DataFrame:\n    """Parse ISO-8601 date strings to UTC, optional tz convert, and index."""\n    if date_col not in df.columns:\n        raise KeyError(f"Expected \'{date_col}\' in DataFrame columns.")\n    df[date_col] = pd.to_datetime(df[date_col], utc=True, errors="coerce")\n    if to_ams:\n        df[date_col] = df[date_col].dt.tz_convert("Europe/Amsterdam")\n    df = df.set_index(date_col).sort_index()\n    return df\n\n\ndef main(\n    infile: str = INFILE, outfile: str = OUTFILE, convert_to_ams: bool = CONVERT_TO_AMS\n) -> None:\n    t0 = time.perf_counter()\n\n    # 1) Load\n    df = pd.read_parquet(infile)\n    t1 = time.perf_counter()\n\n    # 2) Expand nested dicts (vectorized, type-checker friendly)\n    df = expand_data_column(df, data_col="data")\n    t2 = time.perf_counter()\n\n    # 3) Parse date and set index\n    df = parse_and_index_date(df, date_col="date", to_ams=convert_to_ams)\n    t3 = time.perf_counter()\n\n    # 4) Dtype cleanup\n    df = coerce_dtypes(df)\n    t4 = time.perf_counter()\n\n    # 5) Ensure output directory exists, then save (keep time index)\n    out_path = Path(outfile)\n    out_path.parent.mkdir(parents=True, exist_ok=True)\n    df.to_parquet(out_path, index=True)\n    t5 = time.perf_counter()\n\n    # 6) Sanity + timings\n    print(df.head(5))\n    print()\n    print(df.info())\n\n    print("\\n— Timing —")\n    print(f"Load parquet:        {t1 - t0:6.2f}s")\n    print(f"Expand (from_records):{t2 - t1:6.2f}s")\n    print(f"Datetime/index:      {t3 - t2:6.2f}s")\n    print(f"Dtype cleanup:       {t4 - t3:6.2f}s")\n    print(f"Save expanded:       {t5 - t4:6.2f}s")\n    print(f"Total:               {t5 - t0:6.2f}s")\n\n\nif __name__ == "__main__":\n    main()\n',
}

_MODULE_CACHE: dict[str, ModuleType] = {}


def _load_embedded_module(name: str) -> ModuleType:
    """Load one embedded source as an in-memory module without running its __main__ block."""
    if name in _MODULE_CACHE:
        return _MODULE_CACHE[name]
    if name not in _EMBEDDED_SOURCES:
        raise KeyError(f"Unknown embedded module: {name}")
    module = ModuleType(name)
    module.__file__ = f"<embedded:{name}>"
    module.__name__ = name
    code = compile(_EMBEDDED_SOURCES[name], module.__file__, "exec")
    exec(code, module.__dict__)
    _MODULE_CACHE[name] = module
    return module


@contextlib.contextmanager
def _argv(argv: Sequence[str]) -> Iterator[None]:
    old = sys.argv[:]
    sys.argv = list(argv)
    try:
        yield
    finally:
        sys.argv = old


def _delegate(module_name: str, display_name: str, args: Sequence[str]) -> None:
    module = _load_embedded_module(module_name)
    with _argv([display_name, *args]):
        module.main()


def run_all(args: argparse.Namespace) -> None:
    """Run the default end-to-end pipeline with optional model training."""
    _load_embedded_module("data_pipeline")
    _load_embedded_module("clean_analyze")

    print("\n=== 1/3 DATA PIPELINE ===", flush=True)
    data_args = ["all"]
    if args.recursive_news:
        data_args.append("--recursive-news")
    _delegate("data_pipeline", "data", data_args)

    print("\n=== 2/3 CLEAN FEATURE DATASET + ANALYSIS ===", flush=True)
    clean_args = [
        "all",
        "--input", args.model_dataset,
        "--output", args.clean_dataset,
        "--threshold", str(args.corr_threshold),
    ]
    if args.heatmap_output:
        clean_args += ["--heatmap-output", args.heatmap_output]
    if args.plot:
        clean_args.append("--plot")
    _delegate("clean_analyze", "clean-analyze", clean_args)

    if args.train == "none":
        print("\n=== DONE ===", flush=True)
        print(f"Model dataset:       {args.model_dataset}")
        print(f"Clean model dataset: {args.clean_dataset}")
        return

    print("\n=== 3/3 MODEL TRAINING ===", flush=True)
    train_args = [args.train, "--data", args.clean_dataset, "--outdir", args.train_outdir]
    if args.gpu is not None:
        train_args += ["--gpu", str(args.gpu)]
    if args.auto_threshold:
        train_args.append("--auto_threshold")
    if args.train == "random-search":
        train_args += ["--trials", str(args.trials), "--max_epochs", str(args.max_epochs)]
    elif args.train == "walk-forward":
        train_args += ["--epochs", str(args.epochs), "--lookback", str(args.lookback)]
    _delegate("lstm_training", "train", train_args)

    print("\n=== DONE ===", flush=True)


def build_parser() -> argparse.ArgumentParser:
    parser = argparse.ArgumentParser(
        description="One pipeline for fetching, preprocessing, dataset construction, feature analysis, and LSTM training."
    )
    sub = parser.add_subparsers(dest="command", required=True)

    p = sub.add_parser("fetch", help="Fetch StockData EOD or intraday data. Remaining args match the old fetch script.")
    p.add_argument("fetch_args", nargs=argparse.REMAINDER, help="Arguments passed to the embedded StockData fetcher")

    p = sub.add_parser("data", help="Run data preparation/audit subcommands.")
    p.add_argument("data_args", nargs=argparse.REMAINDER, help="Arguments passed to the embedded data pipeline")

    p = sub.add_parser("clean-analyze", help="Clean model dataset and/or run feature diagnostics.")
    p.add_argument("clean_args", nargs=argparse.REMAINDER, help="Arguments passed to the embedded clean/analyze utility")

    p = sub.add_parser("train", help="Run LSTM random-search or walk-forward.")
    p.add_argument("train_args", nargs=argparse.REMAINDER, help="Arguments passed to the embedded LSTM training utility")

    p = sub.add_parser("train-basic", help="Run the fixed train/val/test LSTM classifier script.")
    p.add_argument("basic_args", nargs=argparse.REMAINDER, help="Arguments passed to the embedded basic LSTM trainer")

    p = sub.add_parser("preprocess-minute", help="Expand nested intraday parquet data column and write cleaned parquet.")
    p.add_argument("--input", default=None, help="Input parquet. Defaults to embedded script default.")
    p.add_argument("--output", default=None, help="Output parquet. Defaults to embedded script default.")
    p.add_argument("--to-ams", action="store_true", help="Convert timestamps to Europe/Amsterdam before indexing.")

    p = sub.add_parser("all", help="Run default data build -> clean/analyze -> optional model training.")
    p.add_argument("--recursive-news", action="store_true", help="Search raw news CSVs recursively.")
    p.add_argument("--model-dataset", default="/home/zammorak/thesis/data/model_feed/model_dataset.csv")
    p.add_argument("--clean-dataset", default="/home/zammorak/thesis/data/model_feed/model_dataset_clean.csv")
    p.add_argument("--corr-threshold", type=float, default=0.85)
    p.add_argument("--heatmap-output", default=None, help="Optional path for saved correlation heatmap.")
    p.add_argument("--plot", action="store_true", help="Show heatmap interactively during analysis.")
    p.add_argument("--train", choices=["none", "random-search", "walk-forward"], default="none")
    p.add_argument("--train-outdir", default="/home/zammorak/thesis/models/pipeline_run")
    p.add_argument("--gpu", default=None)
    p.add_argument("--auto-threshold", action="store_true")
    p.add_argument("--trials", type=int, default=50, help="Random-search trials if --train random-search.")
    p.add_argument("--max-epochs", type=int, default=50, help="Random-search max epochs.")
    p.add_argument("--epochs", type=int, default=30, help="Walk-forward epochs.")
    p.add_argument("--lookback", type=int, default=60, help="Walk-forward lookback.")
    p.set_defaults(func=run_all)

    return parser


def main() -> None:
    parser = build_parser()
    args = parser.parse_args()

    if args.command == "fetch":
        inner = args.fetch_args or ["--help"]
        _delegate("stockdata_fetch", "fetch", inner)
    elif args.command == "data":
        inner = args.data_args or ["--help"]
        _delegate("data_pipeline", "data", inner)
    elif args.command == "clean-analyze":
        inner = args.clean_args or ["--help"]
        _delegate("clean_analyze", "clean-analyze", inner)
    elif args.command == "train":
        inner = args.train_args or ["--help"]
        _delegate("lstm_training", "train", inner)
    elif args.command == "train-basic":
        inner = args.basic_args or ["--help"]
        _delegate("lstm_basic", "train-basic", inner)
    elif args.command == "preprocess-minute":
        mod = _load_embedded_module("minute_preprocess")
        infile = args.input if args.input is not None else mod.INFILE
        outfile = args.output if args.output is not None else mod.OUTFILE
        mod.main(infile=infile, outfile=outfile, convert_to_ams=args.to_ams)
    elif args.command == "all":
        args.func(args)
    else:
        parser.error(f"Unknown command: {args.command}")


if __name__ == "__main__":
    main()
